import { GoogleGenAI } from "@google/genai";

const SYSTEM_INSTRUCTION = `
You are "ForeNova Expert", a senior forensic scientist with 30 years of experience in crime scene investigation, laboratory analysis, and expert testimony.
Your goal is to assist students and professionals with forensic science queries ONLY.

RULES:
1. Only answer questions related to forensic science, criminology, criminal law (relevant to forensics), and investigation techniques.
2. If a question is NOT related to forensics (e.g., recipes, generic advice, coding, entertainment), politely decline and state: "I am a forensic expert assistant and can only provide information regarding forensic science and criminology."
3. Provide detailed, accurate, and professional answers.
4. Use terminology like 'Chain of Custody', 'Locard's Principle', 'Luminol', 'Chromatography' where appropriate.
`;

export const getExpertResponse = async (userPrompt: string) => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: userPrompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
        topP: 0.9,
      },
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "I'm having trouble connecting to my database. Please try again later.";
  }
};

import React, { useState, useEffect } from 'react';
import { 
  Home, 
  Search, 
  FlaskConical, 
  PenTool, 
  BookOpen, 
  User, 
  MessageSquare, 
  ShieldCheck, 
  Moon, 
  Sun,
  LayoutDashboard,
  ClipboardList,
  GraduationCap
} from 'lucide-react';
import { UserSession, TabType } from './types';
import Login from './components/Login';
import WelcomeAnimation from './components/WelcomeAnimation';
import Dashboard from './modules/Dashboard';
import EvidenceSimulator from './modules/EvidenceSimulator';
import LabInfo from './modules/LabInfo';
import SketchTool from './modules/SketchTool';
import QuizEngine from './modules/QuizEngine';
import ExamSection from './modules/ExamSection';
import Profile from './modules/Profile';
import ExpertChat from './modules/ExpertChat';

const App: React.FC = () => {
  const [session, setSession] = useState<UserSession | null>(null);
  const [showWelcome, setShowWelcome] = useState(false);
  const [activeTab, setActiveTab] = useState<TabType>('home');
  const [isDarkMode, setIsDarkMode] = useState(true);

  useEffect(() => {
    const savedSession = localStorage.getItem('forenova_session');
    if (savedSession) {
      setSession(JSON.parse(savedSession));
    }
    const savedTheme = localStorage.getItem('forenova_theme');
    if (savedTheme === 'light') setIsDarkMode(false);
  }, []);

  const handleLogin = (username: string) => {
    const newSession: UserSession = {
      username,
      isLoggedIn: true,
      progress: 25,
      quizScores: [],
      joinedAt: new Date().toISOString()
    };
    localStorage.setItem('forenova_session', JSON.stringify(newSession));
    setSession(newSession);
    setShowWelcome(true);
  };

  const handleLogout = () => {
    localStorage.removeItem('forenova_session');
    setSession(null);
    setActiveTab('home');
  };

  const toggleTheme = () => {
    const newMode = !isDarkMode;
    setIsDarkMode(newMode);
    localStorage.setItem('forenova_theme', newMode ? 'dark' : 'light');
  };

  if (!session) {
    return <Login onLogin={handleLogin} darkMode={isDarkMode} />;
  }

  if (showWelcome) {
    return <WelcomeAnimation username={session.username} onComplete={() => setShowWelcome(false)} />;
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'home': return <Dashboard session={session} setActiveTab={setActiveTab} />;
      case 'evidence': return <EvidenceSimulator />;
      case 'lab': return <LabInfo />;
      case 'sketch': return <SketchTool />;
      case 'quiz': return <QuizEngine session={session} setSession={setSession} />;
      case 'exams': return <ExamSection />;
      case 'profile': return <Profile session={session} onLogout={handleLogout} toggleTheme={toggleTheme} isDarkMode={isDarkMode} />;
      case 'expert': return <ExpertChat />;
      default: return <Dashboard session={session} setActiveTab={setActiveTab} />;
    }
  };

  const NavItem = ({ icon: Icon, label, tab }: { icon: any, label: string, tab: TabType }) => (
    <button
      onClick={() => setActiveTab(tab)}
      className={`flex flex-col items-center justify-center py-2 px-1 transition-all ${
        activeTab === tab 
          ? 'text-blue-500 scale-110' 
          : isDarkMode ? 'text-gray-400 hover:text-gray-200' : 'text-gray-500 hover:text-gray-800'
      }`}
    >
      <Icon size={20} />
      <span className="text-[10px] mt-1 font-medium">{label}</span>
    </button>
  );

  return (
    <div className={`min-h-screen pb-20 transition-colors duration-300 ${isDarkMode ? 'bg-slate-950 text-white' : 'bg-slate-50 text-slate-900'}`}>
      {/* Header */}
      <header className={`sticky top-0 z-40 px-4 py-3 flex justify-between items-center backdrop-blur-md border-b ${isDarkMode ? 'border-slate-800 bg-slate-950/80' : 'border-slate-200 bg-white/80'}`}>
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center font-bold text-white shadow-lg shadow-blue-500/20">F</div>
          <h1 className="text-xl font-bold tracking-tight">FORENOVA</h1>
        </div>
        <div className="flex gap-4">
          <button onClick={() => setActiveTab('expert')} className={`p-2 rounded-full ${isDarkMode ? 'bg-slate-800' : 'bg-slate-100'}`}>
            <MessageSquare size={18} />
          </button>
          <button onClick={toggleTheme} className={`p-2 rounded-full ${isDarkMode ? 'bg-slate-800' : 'bg-slate-100'}`}>
            {isDarkMode ? <Sun size={18} /> : <Moon size={18} />}
          </button>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="max-w-4xl mx-auto px-4 pt-4 animate-in fade-in duration-500">
        {renderContent()}
      </main>

      {/* Bottom Navigation */}
      <nav className={`fixed bottom-0 left-0 right-0 z-50 px-2 py-1 border-t transition-colors ${
        isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-200 shadow-2xl shadow-black/20'
      }`}>
        <div className="max-w-4xl mx-auto grid grid-cols-7 items-center">
          <NavItem icon={LayoutDashboard} label="Home" tab="home" />
          <NavItem icon={ShieldCheck} label="Evidence" tab="evidence" />
          <NavItem icon={FlaskConical} label="Lab" tab="lab" />
          <NavItem icon={PenTool} label="Sketch" tab="sketch" />
          <NavItem icon={BookOpen} label="Quiz" tab="quiz" />
          <NavItem icon={GraduationCap} label="Exams" tab="exams" />
          <NavItem icon={User} label="Profile" tab="profile" />
        </div>
      </nav>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Fingerprint, Shield, ArrowRight } from 'lucide-react';

interface LoginProps {
  onLogin: (username: string) => void;
  darkMode: boolean;
}

const Login: React.FC<LoginProps> = ({ onLogin, darkMode }) => {
  const [username, setUsername] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (username.trim()) {
      onLogin(username);
    }
  };

  return (
    <div className={`min-h-screen flex items-center justify-center p-6 ${darkMode ? 'bg-slate-950 text-white' : 'bg-slate-50 text-slate-900'}`}>
      <div className={`w-full max-w-md p-8 rounded-2xl shadow-2xl ${darkMode ? 'bg-slate-900' : 'bg-white'}`}>
        <div className="flex flex-col items-center mb-8">
          <div className="w-16 h-16 bg-blue-600 rounded-2xl flex items-center justify-center mb-4 rotate-3 shadow-xl shadow-blue-500/30">
            <Fingerprint size={32} className="text-white" />
          </div>
          <h1 className="text-3xl font-bold tracking-tighter">FORENOVA</h1>
          <p className={`text-sm mt-1 ${darkMode ? 'text-slate-400' : 'text-slate-500'}`}>Forensic Intelligence Platform</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div>
            <label className={`block text-xs font-semibold uppercase tracking-wider mb-2 ${darkMode ? 'text-slate-400' : 'text-slate-500'}`}>
              Investigator Username
            </label>
            <input
              autoFocus
              type="text"
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              placeholder="Enter your name"
              className={`w-full px-4 py-3 rounded-xl outline-none border-2 transition-all ${
                darkMode 
                  ? 'bg-slate-800 border-slate-700 focus:border-blue-500' 
                  : 'bg-slate-100 border-slate-200 focus:border-blue-500'
              }`}
            />
          </div>

          <button
            type="submit"
            disabled={!username.trim()}
            className="w-full bg-blue-600 hover:bg-blue-700 disabled:opacity-50 text-white font-bold py-3 rounded-xl transition-all flex items-center justify-center gap-2 group"
          >
            <span>Initialize Access</span>
            <ArrowRight size={18} className="group-hover:translate-x-1 transition-transform" />
          </button>
        </form>

        <div className="mt-8 flex items-center justify-center gap-2">
          <Shield size={14} className="text-blue-500" />
          <span className={`text-[10px] uppercase tracking-widest ${darkMode ? 'text-slate-500' : 'text-slate-400'}`}>Secure Forensic Protocol Enabled</span>
        </div>
      </div>
    </div>
  );
};

export default Login;

import React, { useEffect, useState } from 'react';

interface WelcomeProps {
  username: string;
  onComplete: () => void;
}

const WelcomeAnimation: React.FC<WelcomeProps> = ({ username, onComplete }) => {
  const [dots, setDots] = useState('');

  useEffect(() => {
    const dotInterval = setInterval(() => {
      setDots(prev => (prev.length >= 3 ? '' : prev + '.'));
    }, 400);

    const timer = setTimeout(() => {
      onComplete();
    }, 2500);

    return () => {
      clearInterval(dotInterval);
      clearTimeout(timer);
    };
  }, [onComplete]);

  return (
    <div className="fixed inset-0 z-[100] bg-slate-950 flex flex-col items-center justify-center text-white overflow-hidden">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-blue-900/20 via-transparent to-transparent"></div>

      <div className="relative z-10 text-center animate-bounce">
        <div className="w-24 h-24 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mb-8 mx-auto shadow-[0_0_50px_rgba(59,130,246,0.5)]"></div>
        <h2 className="text-4xl font-bold tracking-tighter mb-2 animate-pulse">
          Welcome <span className="text-blue-500">{username}</span>
        </h2>
        <p className="text-slate-400 font-mono tracking-widest uppercase text-xs">
          Syncing Forensic Database{dots}
        </p>
      </div>

      <div className="absolute bottom-10 left-0 right-0 text-center">
        <div className="w-full max-w-xs h-1 bg-slate-800 rounded-full mx-auto overflow-hidden">
          <div className="h-full bg-blue-500 w-full animate-[loading_2.5s_ease-in-out]"></div>
        </div>
      </div>

      <style>{`
        @keyframes loading {
          0% { transform: translateX(-100%); }
          100% { transform: translateX(0); }
        }
      `}</style>
    </div>
  );
};

export default WelcomeAnimation;

import React, { useState } from 'react';
import { 
  CheckCircle2, 
  AlertCircle, 
  Trash2, 
  Archive, 
  Camera, 
  MapPin, 
  ArrowRight,
  Info
} from 'lucide-react';
import { EVIDENCE_DATA } from '../constants';

const STEPS = [
  'Preparation & Photography',
  'Measurement & Location',
  'Collection & Swabbing',
  'Packaging & Labeling',
  'Chain of Custody'
];

const EvidenceSimulator: React.FC = () => {
  const [selectedEvidence, setSelectedEvidence] = useState(EVIDENCE_DATA[0]);
  const [currentStep, setCurrentStep] = useState(0);
  const [feedback, setFeedback] = useState<{ type: 'success' | 'error', text: string } | null>(null);
  const [selectedTools, setSelectedTools] = useState<string[]>([]);

  const handleToolToggle = (tool: string) => {
    if (selectedTools.includes(tool)) {
      setSelectedTools(prev => prev.filter(t => t !== tool));
    } else {
      setSelectedTools(prev => [...prev, tool]);
    }
  };

  const nextStep = () => {
    if (currentStep === 0 && selectedTools.length === 0) {
      setFeedback({ type: 'error', text: 'Select appropriate tools before proceeding!' });
      return;
    }

    if (currentStep < STEPS.length - 1) {
      setCurrentStep(prev => prev + 1);
      setFeedback(null);
    } else {
      setFeedback({ type: 'success', text: 'Simulation Complete! Evidence successfully preserved.' });
    }
  };

  const restart = () => {
    setCurrentStep(0);
    setSelectedTools([]);
    setFeedback(null);
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h2 className="text-xl font-bold flex items-center gap-2">
          <Archive className="text-blue-500" />
          Evidence Simulation
        </h2>
        <button onClick={restart} className="text-xs bg-slate-800 px-3 py-1 rounded-full flex items-center gap-1 hover:bg-slate-700">
          <Trash2 size={12} /> Reset
        </button>
      </div>

      {/* Select Evidence Type */}
      <div className="flex overflow-x-auto gap-2 pb-2 scrollbar-hide">
        {EVIDENCE_DATA.map(ev => (
          <button
            key={ev.id}
            onClick={() => { setSelectedEvidence(ev); restart(); }}
            className={`px-4 py-2 rounded-xl text-xs whitespace-nowrap transition-all flex-shrink-0 border-2 ${
              selectedEvidence.id === ev.id 
                ? 'bg-blue-600 border-blue-600 text-white font-bold' 
                : 'bg-slate-900 border-slate-800 text-slate-400'
            }`}
          >
            {ev.name}
          </button>
        ))}
      </div>

      {/* Step Indicator */}
      <div className="flex justify-between relative">
        <div className="absolute top-1/2 left-0 right-0 h-0.5 bg-slate-800 -translate-y-1/2 -z-10"></div>
        {STEPS.map((step, idx) => (
          <div key={idx} className="flex flex-col items-center gap-1">
            <div className={`w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-bold transition-all z-10 ${
              idx < currentStep ? 'bg-green-500 text-white' : 
              idx === currentStep ? 'bg-blue-600 text-white ring-4 ring-blue-600/20' : 
              'bg-slate-800 text-slate-500'
            }`}>
              {idx < currentStep ? <CheckCircle2 size={12} /> : idx + 1}
            </div>
          </div>
        ))}
      </div>

      {/* Simulation Area */}
      <div className="bg-slate-900 rounded-2xl p-6 border border-slate-800 min-h-[350px] flex flex-col">
        <div className="mb-4">
          <h3 className="text-lg font-bold text-blue-400">{STEPS[currentStep]}</h3>
          <p className="text-xs text-slate-400 mt-1">Simulating collection of: {selectedEvidence.name}</p>
        </div>

        <div className="flex-1 flex flex-col items-center justify-center space-y-4">
          {currentStep === 0 && (
            <div className="w-full space-y-4">
              <div className="flex items-center gap-4 bg-slate-800/50 p-4 rounded-xl">
                <Camera size={32} className="text-slate-500" />
                <p className="text-xs">Take wide-angle and close-up photographs of the evidence in-situ.</p>
              </div>
              <h4 className="text-xs font-bold uppercase tracking-widest text-slate-500">Select Essential Tools</h4>
              <div className="grid grid-cols-2 gap-2">
                {selectedEvidence.toolsNeeded.concat(['Generic Brush', 'Plastic Bag', 'Hammer']).map(tool => (
                  <button
                    key={tool}
                    onClick={() => handleToolToggle(tool)}
                    className={`p-3 rounded-lg text-[11px] text-left transition-all border ${
                      selectedTools.includes(tool) 
                        ? 'bg-blue-600/20 border-blue-500 text-blue-200' 
                        : 'bg-slate-800 border-slate-700 text-slate-400'
                    }`}
                  >
                    {tool}
                  </button>
                ))}
              </div>
            </div>
          )}

          {currentStep === 1 && (
            <div className="w-full flex flex-col items-center gap-4">
              <div className="w-32 h-32 bg-slate-800 rounded-lg flex items-center justify-center border-2 border-dashed border-slate-700">
                <MapPin size={40} className="text-blue-500 animate-bounce" />
              </div>
              <p className="text-center text-sm text-slate-300">Plotting coordinates using the <span className="text-blue-400 font-bold">Baseline Method</span>. Measuring distance from fixed reference points.</p>
            </div>
          )}

          {currentStep === 2 && (
            <div className="w-full text-center space-y-4">
              <div className="inline-block p-4 bg-blue-500/10 rounded-full border border-blue-500/30">
                <Info size={30} className="text-blue-500" />
              </div>
              <div className="space-y-2">
                <h4 className="font-bold text-sm">Action Technique: {selectedEvidence.category}</h4>
                <p className="text-xs text-slate-400 leading-relaxed">
                  Carefully {selectedEvidence.name === 'Liquid Blood' ? 'swab the surface using sterile cotton' : 'lift the print using adhesive tape'}. Ensure no cross-contamination.
                </p>
              </div>
            </div>
          )}

          {currentStep >= 3 && currentStep < 5 && (
            <div className="w-full text-center space-y-6">
              <div className="bg-slate-800 p-6 rounded-2xl border-2 border-blue-500/50 relative overflow-hidden">
                <div className="absolute top-0 right-0 px-2 py-0.5 bg-blue-500 text-[8px] font-bold uppercase">SECURED</div>
                <div className="text-left font-mono text-[10px] space-y-1">
                  <p>ID: #EV-{Math.floor(Math.random() * 9000) + 1000}</p>
                  <p>PACKAGING: {selectedEvidence.packaging}</p>
                  <p>STORAGE: {selectedEvidence.storage}</p>
                  <p>TEMP: {selectedEvidence.temperature}</p>
                </div>
              </div>
              <div className="text-xs text-slate-400">Apply the evidence tape and initial across the seal.</div>
            </div>
          )}

          {feedback && (
            <div className={`mt-4 w-full p-3 rounded-xl flex items-center gap-3 animate-in slide-in-from-bottom-2 ${
              feedback.type === 'success' ? 'bg-green-500/20 text-green-300 border border-green-500/50' : 'bg-red-500/20 text-red-300 border border-red-500/50'
            }`}>
              {feedback.type === 'success' ? <CheckCircle2 size={18} /> : <AlertCircle size={18} />}
              <p className="text-xs font-medium">{feedback.text}</p>
            </div>
          )}
        </div>

        <button 
          onClick={nextStep}
          className="mt-6 w-full py-3 bg-blue-600 rounded-xl font-bold flex items-center justify-center gap-2 hover:bg-blue-700 transition-colors shadow-lg shadow-blue-500/20"
        >
          {currentStep === STEPS.length - 1 ? 'Finish Simulation' : 'Continue Step'}
