import React, { useRef, useState, useEffect } from 'react';
import { 
  Square, 
  Circle as CircleIcon, 
  Minus, 
  Undo2, 
  Redo2, 
  Download, 
  Plus, 
  Trash2, 
  Move,
  Type,
  Maximize2
} from 'lucide-react';

const ASSETS = [
  { id: 'body', name: 'Body Outline', icon: '👤' },
  { id: 'weapon', name: 'Firearm', icon: '🔫' },
  { id: 'blood', name: 'Splatter', icon: '🩸' },
  { id: 'furniture', name: 'Table', icon: '🪑' },
  { id: 'car', name: 'Vehicle', icon: '🚗' },
];

interface Element {
  id: number;
  type: string;
  x: number;
  y: number;
  label: string;
  icon?: string;
}

const SketchTool: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [elements, setElements] = useState<Element[]>([]);
  const [activeTool, setActiveTool] = useState<'move' | 'rect' | 'circle' | 'line' | 'text'>('move');
  const [selectedId, setSelectedId] = useState<number | null>(null);
  const [history, setHistory] = useState<Element[][]>([]);
  const [is3DMode, setIs3DMode] = useState(false);

  useEffect(() => {
    draw();
  }, [elements, activeTool, selectedId, is3DMode]);

  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // Draw Grid
    ctx.strokeStyle = '#1e293b';
    ctx.lineWidth = 0.5;
    for (let x = 0; x < canvas.width; x += 20) {
      ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, canvas.height); ctx.stroke();
    }
    for (let y = 0; y < canvas.height; y += 20) {
      ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(canvas.width, y); ctx.stroke();
    }

    // Draw Elements
    elements.forEach(el => {
      ctx.fillStyle = el.id === selectedId ? '#3b82f6' : '#ffffff';
      ctx.font = '24px serif';
      if (el.icon) {
        ctx.fillText(el.icon, el.x - 12, el.y + 8);
      } else {
        ctx.beginPath();
        ctx.arc(el.x, el.y, 10, 0, Math.PI * 2);
        ctx.fill();
      }

      ctx.font = '10px Inter';
      ctx.fillStyle = '#94a3b8';
      ctx.fillText(el.label, el.x - 10, el.y + 25);

      if (el.id === selectedId) {
        ctx.strokeStyle = '#3b82f6';
        ctx.lineWidth = 1;
        ctx.strokeRect(el.x - 18, el.y - 18, 36, 36);
      }
    });

    // 3D Perspective Simulation (Visual cue)
    if (is3DMode) {
      ctx.fillStyle = 'rgba(59, 130, 246, 0.1)';
      ctx.beginPath();
      ctx.moveTo(0, canvas.height);
      ctx.lineTo(canvas.width / 4, canvas.height / 2);
      ctx.lineTo(canvas.width * 3 / 4, canvas.height / 2);
      ctx.lineTo(canvas.width, canvas.height);
      ctx.fill();
    }
  };

  const addElement = (icon: string, name: string) => {
    const newEl: Element = {
      id: Date.now(),
      type: 'icon',
      x: 150,
      y: 150,
      label: name,
      icon
    };
    setHistory(prev => [...prev, elements]);
    setElements([...elements, newEl]);
    setSelectedId(newEl.id);
  };

  const handleCanvasClick = (e: React.MouseEvent<HTMLCanvasElement>) => {
    const rect = canvasRef.current?.getBoundingClientRect();
    if (!rect) return;
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    // Hit test
    const clickedEl = elements.find(el => Math.abs(el.x - x) < 20 && Math.abs(el.y - y) < 20);
    if (clickedEl) {
      setSelectedId(clickedEl.id);
    } else {
      setSelectedId(null);
    }
  };

  const handleMouseMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
    if (selectedId && e.buttons === 1) {
      const rect = canvasRef.current?.getBoundingClientRect();
      if (!rect) return;
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;

      setElements(prev => prev.map(el => el.id === selectedId ? { ...el, x, y } : el));
    }
  };

  const deleteSelected = () => {
    if (selectedId) {
      setHistory(prev => [...prev, elements]);
      setElements(prev => prev.filter(el => el.id !== selectedId));
      setSelectedId(null);
    }
  };

  const undo = () => {
    if (history.length > 0) {
      const prev = history[history.length - 1];
      setElements(prev);
      setHistory(prev => prev.slice(0, -1));
    }
  };

  const exportSketch = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const link = document.createElement('a');
    link.download = `forenova-sketch-${Date.now()}.png`;
    link.href = canvas.toDataURL();
    link.click();
  };

  return (
    <div className="space-y-4 h-full">
      <div className="flex items-center justify-between">
        <h2 className="text-xl font-bold flex items-center gap-2">
          <Maximize2 className="text-blue-500" />
          Crime Scene Builder
        </h2>
        <div className="flex gap-2">
          <button onClick={undo} className="p-2 bg-slate-800 rounded-lg"><Undo2 size={16} /></button>
          <button onClick={exportSketch} className="p-2 bg-blue-600 rounded-lg"><Download size={16} /></button>
        </div>
      </div>

      <div className="grid grid-cols-4 gap-2">
        <button 
          onClick={() => setIs3DMode(!is3DMode)}
          className={`col-span-2 py-2 rounded-xl text-xs font-bold transition-all border-2 ${
            is3DMode ? 'bg-blue-600 border-blue-600' : 'bg-slate-900 border-slate-800 text-slate-400'
          }`}
        >
          {is3DMode ? '3D VIEW ACTIVE' : 'SWITCH TO 3D'}
        </button>
        <button onClick={deleteSelected} className="py-2 bg-rose-900/40 border border-rose-500/30 text-rose-300 rounded-xl flex items-center justify-center gap-1 text-[10px] font-bold">
          <Trash2 size={12} /> REMOVE
        </button>
        <button onClick={() => setElements([])} className="py-2 bg-slate-900 border border-slate-800 text-slate-400 rounded-xl text-[10px] font-bold">
          CLEAR
        </button>
      </div>

      <div className="relative bg-slate-900 rounded-2xl border-4 border-slate-800 overflow-hidden touch-none">
        <canvas
          ref={canvasRef}
          width={350}
          height={350}
          onClick={handleCanvasClick}
          onMouseMove={handleMouseMove}
          className="w-full cursor-crosshair"
        />

        {/* Quick Toolbox Overlay */}
        <div className="absolute top-2 left-2 flex flex-col gap-2">
          {ASSETS.map(asset => (
            <button
              key={asset.id}
              onClick={() => addElement(asset.icon, asset.name)}
              className="w-10 h-10 bg-slate-800 hover:bg-slate-700 rounded-xl flex items-center justify-center shadow-lg border border-slate-700"
              title={asset.name}
            >
              <span className="text-lg">{asset.icon}</span>
            </button>
          ))}
        </div>

        <div className="absolute bottom-2 left-2 right-2 flex justify-center">
          <div className="bg-slate-950/80 backdrop-blur px-4 py-1.5 rounded-full border border-slate-800 flex gap-4 text-[9px] uppercase tracking-widest font-bold text-slate-400">
            <span className="flex items-center gap-1"><Square size={10} /> {elements.length} Elements</span>
            <span className="flex items-center gap-1 text-blue-500"><Move size={10} /> Drag to position</span>
          </div>
        </div>
      </div>

      <div className="p-4 bg-blue-500/10 border border-blue-500/20 rounded-2xl">
        <h4 className="text-xs font-bold text-blue-400 mb-1">Sketch Requirements</h4>
        <ul className="text-[10px] text-slate-400 space-y-1 list-disc list-inside">
          <li>Compass direction (North) must be indicated.</li>
          <li>All measurements must be from two fixed points.</li>
          <li>Labels must be clear and non-overlapping.</li>
          <li>Include 'Not to Scale' if appropriate.</li>
        </ul>
      </div>
    </div>
  );
};

export default SketchTool;

import React, { useState } from 'react';
import { 
  Trophy, 
  CheckCircle2, 
  XCircle, 
  ArrowRight, 
  RotateCcw,
  Lightbulb
} from 'lucide-react';
import { QUIZ_QUESTIONS } from '../constants';
import { UserSession } from '../types';

interface QuizProps {
  session: UserSession;
  setSession: (session: UserSession) => void;
}

const QuizEngine: React.FC<QuizProps> = ({ session, setSession }) => {
  const [currentIdx, setCurrentIdx] = useState(0);
  const [selectedAnswer, setSelectedAnswer] = useState<number | null>(null);
  const [isAnswered, setIsAnswered] = useState(false);
  const [score, setScore] = useState(0);
  const [quizFinished, setQuizFinished] = useState(false);

  const currentQuestion = QUIZ_QUESTIONS[currentIdx];

  const handleAnswer = (idx: number) => {
    if (isAnswered) return;
    setSelectedAnswer(idx);
    setIsAnswered(true);
    if (idx === currentQuestion.correctAnswer) {
      setScore(prev => prev + 1);
    }
  };

  const handleNext = () => {
    if (currentIdx < QUIZ_QUESTIONS.length - 1) {
      setCurrentIdx(prev => prev + 1);
      setSelectedAnswer(null);
      setIsAnswered(false);
    } else {
      setQuizFinished(true);
      const newScores = [...session.quizScores, score];
      setSession({
        ...session,
        quizScores: newScores,
        progress: Math.min(100, session.progress + 10)
      });
    }
  };

  const restart = () => {
    setCurrentIdx(0);
    setSelectedAnswer(null);
    setIsAnswered(false);
    setScore(0);
    setQuizFinished(false);
  };

  if (quizFinished) {
    return (
      <div className="flex flex-col items-center justify-center space-y-8 py-10 animate-in zoom-in duration-500">
        <div className="relative">
          <div className="w-32 h-32 bg-blue-600 rounded-full flex items-center justify-center shadow-[0_0_50px_rgba(59,130,246,0.5)]">
            <Trophy size={60} className="text-white" />
          </div>
          <div className="absolute -top-2 -right-2 bg-emerald-500 text-white px-3 py-1 rounded-full font-bold text-sm">
            {Math.round((score / QUIZ_QUESTIONS.length) * 100)}%
          </div>
        </div>

        <div className="text-center">
          <h2 className="text-3xl font-bold">Training Complete!</h2>
          <p className="text-slate-400 mt-2">You scored {score} out of {QUIZ_QUESTIONS.length}</p>
        </div>

        <div className="w-full space-y-3">
          <button 
            onClick={restart}
            className="w-full py-4 bg-blue-600 hover:bg-blue-700 text-white font-bold rounded-2xl flex items-center justify-center gap-2 transition-all"
          >
            <RotateCcw size={20} /> Try Again
          </button>
          <button className="w-full py-4 bg-slate-900 border border-slate-800 text-slate-300 font-bold rounded-2xl">
            Review Answers
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h2 className="text-xl font-bold">Knowledge Quiz</h2>
        <span className="text-xs font-mono text-blue-500">QUESTION {currentIdx + 1}/{QUIZ_QUESTIONS.length}</span>
      </div>

      <div className="w-full h-1.5 bg-slate-800 rounded-full overflow-hidden">
        <div 
          className="h-full bg-blue-500 transition-all duration-500" 
          style={{ width: `${((currentIdx + 1) / QUIZ_QUESTIONS.length) * 100}%` }}
        ></div>
      </div>

      <div className="bg-slate-900/50 p-6 rounded-3xl border border-slate-800 space-y-6">
        <h3 className="text-lg font-semibold leading-relaxed">
          {currentQuestion.question}
        </h3>

        <div className="space-y-3">
          {currentQuestion.options.map((opt, idx) => (
            <button
              key={idx}
              disabled={isAnswered}
              onClick={() => handleAnswer(idx)}
              className={`w-full p-4 rounded-2xl border-2 text-left transition-all relative flex items-center justify-between group ${
                isAnswered 
                  ? idx === currentQuestion.correctAnswer 
                    ? 'bg-emerald-500/10 border-emerald-500 text-emerald-300' 
                    : idx === selectedAnswer 
                      ? 'bg-rose-500/10 border-rose-500 text-rose-300' 
                      : 'bg-slate-900 border-slate-800 opacity-50'
                  : 'bg-slate-800/50 border-slate-700 hover:border-blue-500/50 hover:bg-slate-800'
              }`}
            >
              <span className="font-medium text-sm">{opt}</span>
              {isAnswered && idx === currentQuestion.correctAnswer && <CheckCircle2 size={18} className="text-emerald-500" />}
              {isAnswered && idx === selectedAnswer && idx !== currentQuestion.correctAnswer && <XCircle size={18} className="text-rose-500" />}
            </button>
          ))}
        </div>

        {isAnswered && (
          <div className="bg-blue-600/10 p-4 rounded-2xl border border-blue-500/20 animate-in slide-in-from-top-2">
            <div className="flex items-center gap-2 text-blue-400 font-bold text-xs uppercase tracking-widest mb-2">
              <Lightbulb size={14} /> Explanation
            </div>
            <p className="text-xs text-slate-300 leading-relaxed">
              {currentQuestion.explanation}
            </p>
          </div>
        )}

        <button
          disabled={!isAnswered}
          onClick={handleNext}
          className="w-full py-4 bg-blue-600 hover:bg-blue-700 disabled:opacity-50 text-white font-bold rounded-2xl flex items-center justify-center gap-2 transition-all shadow-lg shadow-blue-500/20"
        >
          {currentIdx === QUIZ_QUESTIONS.length - 1 ? 'Finish Quiz' : 'Next Question'}
          <ArrowRight size={20} />
        </button>
      </div>
    </div>
  );
};

export default QuizEngine;

