const OBJECT_TYPES = [
  'Evidence Marker',
  'Victim',
  'Weapon (Firearm)',
  'Weapon (Knife)',
  'Furniture (Table)',
  'Furniture (Chair)',
  'Bloodstain',
  'Vehicle',
  'Doorway'
];

const SketchTool: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [room, setRoom] = useState<RoomDimensions>({ width: 6, length: 5 });
  const [objects, setObjects] = useState<SceneObject[]>([]);
  const [currentObject, setCurrentObject] = useState<Omit<SceneObject, 'id'>>({
    type: 'Evidence Marker',
    label: '',
    x: 0,
    y: 0,
    width: 0.5,
    depth: 0.5,
    rotation: 0
  });

  const pixelsPerMeter = 60;

  useEffect(() => {
    draw();
  }, [room, objects]);

  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Clear and set dimensions based on room
    const padding = 60;
    canvas.width = room.width * pixelsPerMeter + padding * 2;
    canvas.height = room.length * pixelsPerMeter + padding * 2;
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    const startX = padding;
    const startY = padding;

    // Background color for room area
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(startX, startY, room.width * pixelsPerMeter, room.length * pixelsPerMeter);

    // Draw Grid Dots
    ctx.fillStyle = '#cbd5e1';
    for (let x = 0; x <= room.width; x++) {
      for (let y = 0; y <= room.length; y++) {
        ctx.beginPath();
        ctx.arc(startX + x * pixelsPerMeter, startY + y * pixelsPerMeter, 1, 0, Math.PI * 2);
        ctx.fill();
      }
    }

    // Grid Label
    ctx.font = '10px Inter';
    ctx.fillStyle = '#94a3b8';
    ctx.fillText('1 Grid Square = 1 Meter', startX + 5, startY + 15);

    // Draw Room Borders
    ctx.strokeStyle = '#1e293b';
    ctx.lineWidth = 2;
    ctx.strokeRect(startX, startY, room.width * pixelsPerMeter, room.length * pixelsPerMeter);

    // Draw Dimensions Labels
    ctx.fillStyle = '#94a3b8';
    ctx.textAlign = 'center';
    ctx.font = 'bold 12px Inter';
    ctx.fillText(`${room.width}m`, startX + (room.width * pixelsPerMeter) / 2, startY - 15);

    ctx.save();
    ctx.translate(startX - 20, startY + (room.length * pixelsPerMeter) / 2);
    ctx.rotate(-Math.PI / 2);
    ctx.fillText(`${room.length}m`, 0, 0);
    ctx.restore();

    // Draw Objects
    objects.forEach((obj) => {
      ctx.save();
      // Translate to object center
      const drawX = startX + obj.x * pixelsPerMeter;
      const drawY = startY + obj.y * pixelsPerMeter;
      const drawW = obj.width * pixelsPerMeter;
      const drawD = obj.depth * pixelsPerMeter;

      ctx.translate(drawX, drawY);
      ctx.rotate((obj.rotation * Math.PI) / 180);

      // Object Body
      ctx.fillStyle = '#3b82f6';
      ctx.fillRect(-drawW / 2, -drawD / 2, drawW, drawD);
      ctx.strokeStyle = '#1d4ed8';
      ctx.lineWidth = 1;
      ctx.strokeRect(-drawW / 2, -drawD / 2, drawW, drawD);

      // Label inside object
      ctx.rotate(-(obj.rotation * Math.PI) / 180); // Un-rotate for text readability? No, usually labels stay oriented
      ctx.fillStyle = '#ffffff';
      ctx.font = 'bold 8px Inter';
      ctx.textAlign = 'center';
      ctx.fillText(obj.label || obj.type.split(' ')[0], 0, 3);

      ctx.restore();
    });
  };

  const addObject = () => {
    const newObject: SceneObject = {
      ...currentObject,
      id: Date.now().toString()
    };
    setObjects([...objects, newObject]);
    setCurrentObject({ ...currentObject, label: '' }); // Reset label only
  };

  const removeObject = (id: string) => {
    setObjects(objects.filter(o => o.id !== id));
  };

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-12 gap-8">
        {/* Left Column: Inputs */}
        <div className="col-span-12 lg:col-span-4 space-y-6">
          <div className="bg-[#161b2a] border border-slate-800 rounded-xl overflow-hidden">
            <div className="p-4 border-b border-slate-800 flex items-center gap-3">
              <Ruler size={20} className="text-blue-500" />
              <div>
                <h2 className="font-bold text-lg">Measurement Input</h2>
                <p className="text-[10px] text-slate-500 uppercase tracking-widest">Define room and place objects</p>
              </div>
            </div>

            <div className="p-6 space-y-8">
              {/* Room Dimensions Section */}
              <div className="space-y-4">
                <h3 className="text-[11px] font-bold text-slate-500 uppercase tracking-widest">Room Dimensions (Meters)</h3>
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-1.5">
                    <label className="text-xs text-slate-400">Width (X)</label>
                    <input 
                      type="number" 
                      value={room.width}
                      onChange={(e) => setRoom({ ...room, width: Number(e.target.value) })}
                      className="w-full bg-[#0a0e17] border border-slate-800 rounded-lg px-3 py-2 text-sm focus:border-blue-500 outline-none" 
                    />
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-xs text-slate-400">Length (Y)</label>
                    <input 
                      type="number" 
                      value={room.length}
                      onChange={(e) => setRoom({ ...room, length: Number(e.target.value) })}
                      className="w-full bg-[#0a0e17] border border-slate-800 rounded-lg px-3 py-2 text-sm focus:border-blue-500 outline-none" 
                    />
                  </div>
                </div>
              </div>

              {/* Add Scene Object Section */}
              <div className="space-y-4 p-5 bg-[#0a0e17]/50 rounded-xl border border-slate-800">
                <h3 className="text-[11px] font-bold text-slate-500 uppercase tracking-widest">Add Scene Object</h3>

                <div className="space-y-3">
                  <div className="space-y-1.5">
                    <label className="text-xs text-slate-400">Type</label>
                    <div className="relative">
                      <select 
                        value={currentObject.type}
                        onChange={(e) => setCurrentObject({ ...currentObject, type: e.target.value })}
                        className="w-full bg-[#0a0e17] border border-slate-800 rounded-lg px-3 py-2 text-sm focus:border-blue-500 outline-none appearance-none cursor-pointer"
                      >
                        {OBJECT_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
                      </select>
                      <ChevronDown size={16} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-500 pointer-events-none" />
                    </div>
                  </div>

                  <div className="space-y-1.5">
                    <label className="text-xs text-slate-400">Label / ID</label>
                    <input 
                      type="text" 
                      placeholder="e.g. Knife, Table, Victim"
                      value={currentObject.label}
                      onChange={(e) => setCurrentObject({ ...currentObject, label: e.target.value })}
                      className="w-full bg-[#0a0e17] border border-slate-800 rounded-lg px-3 py-2 text-sm focus:border-blue-500 outline-none" 
                    />
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-1.5">
                      <label className="text-xs text-slate-400">Pos X (m)</label>
                      <input 
                        type="number" step="0.1" 
                        value={currentObject.x}
                        onChange={(e) => setCurrentObject({ ...currentObject, x: Number(e.target.value) })}
                        className="w-full bg-[#0a0e17] border border-slate-800 rounded-lg px-3 py-2 text-sm focus:border-blue-500 outline-none" 
                      />
                    </div>
                    <div className="space-y-1.5">
                      <label className="text-xs text-slate-400">Pos Y (m)</label>
                      <input 
                        type="number" step="0.1" 
                        value={currentObject.y}
                        onChange={(e) => setCurrentObject({ ...currentObject, y: Number(e.target.value) })}
                        className="w-full bg-[#0a0e17] border border-slate-800 rounded-lg px-3 py-2 text-sm focus:border-blue-500 outline-none" 
                      />
                    </div>
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-1.5">
                      <label className="text-xs text-slate-400">Width (m)</label>
                      <input 
                        type="number" step="0.1" 
                        value={currentObject.width}
                        onChange={(e) => setCurrentObject({ ...currentObject, width: Number(e.target.value) })}
                        className="w-full bg-[#0a0e17] border border-slate-800 rounded-lg px-3 py-2 text-sm focus:border-blue-500 outline-none" 
                      />
                    </div>
                    <div className="space-y-1.5">
                      <label className="text-xs text-slate-400">Depth (m)</label>
                      <input 
                        type="number" step="0.1" 
                        value={currentObject.depth}
                        onChange={(e) => setCurrentObject({ ...currentObject, depth: Number(e.target.value) })}
                        className="w-full bg-[#0a0e17] border border-slate-800 rounded-lg px-3 py-2 text-sm focus:border-blue-500 outline-none" 
                      />
                    </div>
                  </div>

                  <div className="space-y-1.5 pt-2">
                    <div className="flex justify-between">
                      <label className="text-xs text-slate-400">Rotation (Degrees)</label>
                      <span className="text-[10px] text-slate-500 font-mono">{currentObject.rotation}°</span>
                    </div>
                    <input 
                      type="range" min="0" max="360" step="5"
                      value={currentObject.rotation}
                      onChange={(e) => setCurrentObject({ ...currentObject, rotation: Number(e.target.value) })}
                      className="w-full h-1.5 bg-[#0a0e17] rounded-lg appearance-none cursor-pointer accent-blue-500" 
                    />
                  </div>

                  <button 
                    onClick={addObject}
                    className="w-full mt-4 bg-blue-600 hover:bg-blue-700 text-white py-2 rounded-lg text-sm font-bold flex items-center justify-center gap-2 transition-all"
