import React, { useState, useCallback } from 'react';
import { 
  CheckCircle2, 
  AlertCircle, 
  Trash2, 
  Archive, 
  Camera, 
  MapPin, 
  ArrowRight,
  Info
} from 'lucide-react';
import { EVIDENCE_DATA } from '../constants';

const STEPS = [
  'Preparation & Photography',
  'Measurement & Location',
  'Collection & Swabbing',
  'Packaging & Labeling',
  'Chain of Custody'
];

const EvidenceSimulator: React.FC = () => {
  const [selectedEvidence, setSelectedEvidence] = useState(EVIDENCE_DATA[0]);
  const [currentStep, setCurrentStep] = useState(0);
  const [feedback, setFeedback] = useState<{ type: 'success' | 'error', text: string } | null>(null);
  const [selectedTools, setSelectedTools] = useState<string[]>([]);

  // Immersive Forensic Sound Utility
  const playSound = useCallback((type: 'success' | 'error' | 'click') => {
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      if (!AudioContext) return;

      const ctx = new AudioContext();
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();

      osc.connect(gain);
      gain.connect(ctx.destination);

      const now = ctx.currentTime;

      if (type === 'success') {
        osc.type = 'sine';
        osc.frequency.setValueAtTime(880, now);
        osc.frequency.exponentialRampToValueAtTime(1320, now + 0.1);
        gain.gain.setValueAtTime(0.1, now);
        gain.gain.exponentialRampToValueAtTime(0.01, now + 0.2);
        osc.start(now);
        osc.stop(now + 0.2);
      } else if (type === 'error') {
        osc.type = 'sawtooth';
        osc.frequency.setValueAtTime(150, now);
        osc.frequency.exponentialRampToValueAtTime(50, now + 0.3);
        gain.gain.setValueAtTime(0.1, now);
        gain.gain.linearRampToValueAtTime(0, now + 0.3);
        osc.start(now);
        osc.stop(now + 0.3);
      } else {
        // Subtle forensic click
        osc.type = 'sine';
        osc.frequency.setValueAtTime(1500, now);
        gain.gain.setValueAtTime(0.05, now);
        gain.gain.exponentialRampToValueAtTime(0.01, now + 0.05);
        osc.start(now);
        osc.stop(now + 0.05);
      }
    } catch (e) {
      console.warn("Audio Context blocked or unavailable", e);
    }
  }, []);

  const handleToolToggle = (tool: string) => {
    playSound('click');
    if (selectedTools.includes(tool)) {
      setSelectedTools(prev => prev.filter(t => t !== tool));
    } else {
      setSelectedTools(prev => [...prev, tool]);
    }
  };

  const nextStep = () => {
    if (currentStep === 0 && selectedTools.length === 0) {
      playSound('error');
      setFeedback({ type: 'error', text: 'Select appropriate tools before proceeding!' });
      return;
    }

    if (currentStep < STEPS.length - 1) {
      playSound('click');
      setCurrentStep(prev => prev + 1);
      setFeedback(null);
    } else {
      playSound('success');
      setFeedback({ type: 'success', text: 'Simulation Complete! Evidence successfully preserved.' });
    }
  };

  const restart = () => {
    playSound('click');
    setCurrentStep(0);
    setSelectedTools([]);
    setFeedback(null);
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h2 className="text-xl font-bold flex items-center gap-2">
          <Archive className="text-blue-500" />
          Evidence Simulation
        </h2>
        <button onClick={restart} className="text-xs bg-slate-800 px-3 py-1 rounded-full flex items-center gap-1 hover:bg-slate-700">
          <Trash2 size={12} /> Reset
        </button>
      </div>

      {/* Select Evidence Type */}
      <div className="flex overflow-x-auto gap-2 pb-2 scrollbar-hide">
        {EVIDENCE_DATA.map(ev => (
          <button
            key={ev.id}
            onClick={() => { playSound('click'); setSelectedEvidence(ev); restart(); }}
            className={`px-4 py-2 rounded-xl text-xs whitespace-nowrap transition-all flex-shrink-0 border-2 ${
              selectedEvidence.id === ev.id 
                ? 'bg-blue-600 border-blue-600 text-white font-bold' 
                : 'bg-slate-900 border-slate-800 text-slate-400'
            }`}
          >
            {ev.name}
          </button>
        ))}
      </div>

      {/* Step Indicator */}
      <div className="flex justify-between relative">
        <div className="absolute top-1/2 left-0 right-0 h-0.5 bg-slate-800 -translate-y-1/2 -z-10"></div>
        {STEPS.map((step, idx) => (
          <div key={idx} className="flex flex-col items-center gap-1">
            <div className={`w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-bold transition-all z-10 ${
              idx < currentStep ? 'bg-green-500 text-white' : 
              idx === currentStep ? 'bg-blue-600 text-white ring-4 ring-blue-600/20' : 
              'bg-slate-800 text-slate-500'
            }`}>
              {idx < currentStep ? <CheckCircle2 size={12} /> : idx + 1}
            </div>
          </div>
        ))}
      </div>

      {/* Simulation Area */}
      <div className="bg-slate-900 rounded-2xl p-6 border border-slate-800 min-h-[350px] flex flex-col">
        <div className="mb-4">
          <h3 className="text-lg font-bold text-blue-400">{STEPS[currentStep]}</h3>
          <p className="text-xs text-slate-400 mt-1">Simulating collection of: {selectedEvidence.name}</p>
        </div>

        <div className="flex-1 flex flex-col items-center justify-center space-y-4">
          {currentStep === 0 && (
            <div className="w-full space-y-4">
              <div className="flex items-center gap-4 bg-slate-800/50 p-4 rounded-xl">
                <Camera size={32} className="text-slate-500" />
                <p className="text-xs">Take wide-angle and close-up photographs of the evidence in-situ.</p>
              </div>
              <h4 className="text-xs font-bold uppercase tracking-widest text-slate-500">Select Essential Tools</h4>
              <div className="grid grid-cols-2 gap-2">
                {selectedEvidence.toolsNeeded.concat(['Generic Brush', 'Plastic Bag', 'Hammer']).map(tool => (
                  <button
                    key={tool}
                    onClick={() => handleToolToggle(tool)}
                    className={`p-3 rounded-lg text-[11px] text-left transition-all border ${
                      selectedTools.includes(tool) 
                        ? 'bg-blue-600/20 border-blue-500 text-blue-200' 
                        : 'bg-slate-800 border-slate-700 text-slate-400'
                    }`}
                  >
                    {tool}
                  </button>
                ))}
              </div>
            </div>
          )}

          {currentStep === 1 && (
            <div className="w-full flex flex-col items-center gap-4">
              <div className="w-32 h-32 bg-slate-800 rounded-lg flex items-center justify-center border-2 border-dashed border-slate-700">
                <MapPin size={40} className="text-blue-500 animate-bounce" />
              </div>
              <p className="text-center text-sm text-slate-300">Plotting coordinates using the <span className="text-blue-400 font-bold">Baseline Method</span>. Measuring distance from fixed reference points.</p>
            </div>
          )}

          {currentStep === 2 && (
            <div className="w-full text-center space-y-4">
              <div className="inline-block p-4 bg-blue-500/10 rounded-full border border-blue-500/30">
                <Info size={30} className="text-blue-500" />
              </div>
              <div className="space-y-2">
                <h4 className="font-bold text-sm">Action Technique: {selectedEvidence.category}</h4>
                <p className="text-xs text-slate-400 leading-relaxed">
                  Carefully {selectedEvidence.name === 'Liquid Blood' ? 'swab the surface using sterile cotton' : 'lift the print using adhesive tape'}. Ensure no cross-contamination.
                </p>
              </div>
            </div>
          )}

          {currentStep >= 3 && currentStep < 5 && (
            <div className="w-full text-center space-y-6">
              <div className="bg-slate-800 p-6 rounded-2xl border-2 border-blue-500/50 relative overflow-hidden">
                <div className="absolute top-0 right-0 px-2 py-0.5 bg-blue-500 text-[8px] font-bold uppercase">SECURED</div>
                <div className="text-left font-mono text-[10px] space-y-1">
                  <p>ID: #EV-{Math.floor(Math.random() * 9000) + 1000}</p>
                  <p>PACKAGING: {selectedEvidence.packaging}</p>
                  <p>STORAGE: {selectedEvidence.storage}</p>
                  <p>TEMP: {selectedEvidence.temperature}</p>
                </div>
              </div>
              <div className="text-xs text-slate-400">Apply the evidence tape and initial across the seal.</div>
            </div>
          )}

          {feedback && (
            <div className={`mt-4 w-full p-3 rounded-xl flex items-center gap-3 animate-in slide-in-from-bottom-2 ${
              feedback.type === 'success' ? 'bg-green-500/20 text-green-300 border border-green-500/50' : 'bg-red-500/20 text-red-300 border border-red-500/50'
            }`}>
              {feedback.type === 'success' ? <CheckCircle2 size={18} /> : <AlertCircle size={18} />}
              <p className="text-xs font-medium">{feedback.text}</p>
            </div>
          )}
        </div>

        <button 
          onClick={nextStep}
          className="mt-6 w-full py-3 bg-blue-600 rounded-xl font-bold flex items-center justify-center gap-2 hover:bg-blue-700 transition-colors shadow-lg shadow-blue-500/20"
        >
          {currentStep === STEPS.length - 1 ? 'Finish Simulation' : 'Continue Step'}
          <ArrowRight size={18} />
        </button>
      </div>

      <div className="p-4 bg-slate-800/40 rounded-xl border border-slate-800">
        <h4 className="text-[10px] font-bold uppercase tracking-widest text-slate-500 mb-2">Expert Tip</h4>
        <p className="text-xs text-slate-300 italic">"Always maintain the Chain of Custody. If the link breaks, the evidence may be inadmissible in court."</p>
      </div>
    </div>
  );
};

