const SketchTool: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [room, setRoom] = useState<RoomDimensions>({ width: 6, length: 5 });
  const [objects, setObjects] = useState<SceneObject[]>([]);
  const [currentObject, setCurrentObject] = useState<Omit<SceneObject, 'id'>>({
    type: 'Evidence Marker',
    label: '',
    x: 0,
    y: 0,
    width: 0.5,
    depth: 0.5,
    rotation: 0,
    color: COLORS[0].value
  });

  const pixelsPerMeter = 60;

  useEffect(() => {
    draw();
  }, [room, objects]);

  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Clear and set dimensions based on room
    const padding = 60;
    canvas.width = room.width * pixelsPerMeter + padding * 2;
    canvas.height = room.length * pixelsPerMeter + padding * 2;
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    const startX = padding;
    const startY = padding;

    // Background color for room area
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(startX, startY, room.width * pixelsPerMeter, room.length * pixelsPerMeter);

    // Draw Grid Dots
    ctx.fillStyle = '#cbd5e1';
    for (let x = 0; x <= room.width; x++) {
      for (let y = 0; y <= room.length; y++) {
        ctx.beginPath();
        ctx.arc(startX + x * pixelsPerMeter, startY + y * pixelsPerMeter, 1, 0, Math.PI * 2);
        ctx.fill();
      }
    }

    // Grid Label
    ctx.font = '10px Inter';
    ctx.fillStyle = '#94a3b8';
    ctx.fillText('1 Grid Square = 1 Meter', startX + 5, startY + 15);

    // Draw Room Borders
    ctx.strokeStyle = '#1e293b';
    ctx.lineWidth = 2;
    ctx.strokeRect(startX, startY, room.width * pixelsPerMeter, room.length * pixelsPerMeter);

    // Draw Dimensions Labels
    ctx.fillStyle = '#94a3b8';
    ctx.textAlign = 'center';
    ctx.font = 'bold 12px Inter';
    ctx.fillText(`${room.width}m`, startX + (room.width * pixelsPerMeter) / 2, startY - 15);

    ctx.save();
    ctx.translate(startX - 20, startY + (room.length * pixelsPerMeter) / 2);
    ctx.rotate(-Math.PI / 2);
    ctx.fillText(`${room.length}m`, 0, 0);
    ctx.restore();

    // Draw Objects
    objects.forEach((obj) => {
      ctx.save();
      // Translate to object center
      const drawX = startX + obj.x * pixelsPerMeter;
      const drawY = startY + obj.y * pixelsPerMeter;
      const drawW = obj.width * pixelsPerMeter;
      const drawD = obj.depth * pixelsPerMeter;

      ctx.translate(drawX, drawY);
      ctx.rotate((obj.rotation * Math.PI) / 180);

      // Object Body
      ctx.fillStyle = obj.color || '#3b82f6';

      // Handle special shapes based on type
      if (obj.type.includes('Body')) {
        // Simple oval for body
        ctx.beginPath();
        ctx.ellipse(0, 0, drawW / 2, drawD / 2, 0, 0, Math.PI * 2);
        ctx.fill();
        ctx.strokeStyle = 'white';
        ctx.lineWidth = 2;
        ctx.stroke();
      } else if (obj.type.includes('Bloodstain')) {
        // Irregular splatter
        ctx.beginPath();
        for (let i = 0; i < 8; i++) {
          const angle = (i / 8) * Math.PI * 2;
          const r = (drawW / 2) * (0.6 + Math.random() * 0.4);
          const px = Math.cos(angle) * r;
          const py = Math.sin(angle) * r;
          if (i === 0) ctx.moveTo(px, py);
          else ctx.lineTo(px, py);
        }
        ctx.closePath();
        ctx.fill();
      } else {
        // Standard rectangle
        ctx.fillRect(-drawW / 2, -drawD / 2, drawW, drawD);
        ctx.strokeStyle = 'rgba(0,0,0,0.2)';
        ctx.lineWidth = 1;
        ctx.strokeRect(-drawW / 2, -drawD / 2, drawW, drawD);
      }

      // Label inside object
      ctx.rotate(-(obj.rotation * Math.PI) / 180);
      ctx.fillStyle = '#ffffff';
      ctx.font = 'bold 8px Inter';
      ctx.textAlign = 'center';
      ctx.shadowColor = 'black';
      ctx.shadowBlur = 2;
      ctx.fillText(obj.label || obj.type.split(' ')[0], 0, 3);

      ctx.restore();
    });
  };

  const addObject = () => {
    const newObject: SceneObject = {
      ...currentObject,
      id: Date.now().toString()
    };
    setObjects([...objects, newObject]);
    setCurrentObject({ ...currentObject, label: '' }); // Reset label
  };

  const removeObject = (id: string) => {
    setObjects(objects.filter(o => o.id !== id));
  };

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-12 gap-8">
        {/* Left Column: Inputs */}
        <div className="col-span-12 lg:col-span-4 space-y-6">
          <div className="bg-[#161b2a] border border-slate-800 rounded-xl overflow-hidden">
            <div className="p-4 border-b border-slate-800 flex items-center gap-3">
              <Ruler size={20} className="text-blue-500" />
              <div>
                <h2 className="font-bold text-lg">Measurement Input</h2>
                <p className="text-[10px] text-slate-500 uppercase tracking-widest">Define room and place objects</p>
              </div>
            </div>

            <div className="p-6 space-y-8">
              {/* Room Dimensions Section */}
              <div className="space-y-4">
