                }}
                className="flex items-center gap-2 text-xs font-bold text-slate-400 hover:text-white px-3 py-1.5 rounded-lg border border-slate-800 transition-all bg-[#161b2a]"
              >
                <Download size={14} /> Export PNG
              </button>
            </div>
          </div>

          <div className="bg-[#0a0e17] rounded-2xl border border-slate-800 p-8 flex items-center justify-center min-h-[600px] overflow-auto relative group">
            <canvas
              ref={canvasRef}
              className="shadow-2xl shadow-black/50"
            />

            <div className="absolute top-4 right-4 opacity-0 group-hover:opacity-100 transition-opacity">
              <div className="bg-slate-900/80 backdrop-blur px-3 py-1.5 rounded-full border border-slate-800 text-[10px] text-slate-400 font-mono uppercase tracking-widest">
                CAD-Ready Vector Plan
              </div>
            </div>
          </div>

          <div className="p-4 bg-blue-500/5 border border-blue-500/10 rounded-xl flex items-start gap-4">
            <div className="p-2 bg-blue-500/10 rounded-lg text-blue-500">
              <Maximize2 size={18} />
            </div>
            <div>
              <h4 className="text-xs font-bold text-blue-400">Auto-Calibration Active</h4>
              <p className="text-[11px] text-slate-500 leading-relaxed">
                Plan view uses a standardized scale (60px = 1m). All placed objects include coordinate data relative to the primary fixed reference point (bottom-left corner). Shapes are rendering with realistic textures based on type.
              </p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

