    playSound('click');
    setSelectedDailyEvidence(prev => 
      prev.includes(id) ? prev.filter(item => item !== id) : [...prev, id]
    );
  };

  const handleSubmit = () => {
    if (selectedDailyEvidence.length === 0) return;
    playSound('success');
    setIsSubmitted(true);
  };

