import React, { useRef, useState, useEffect, useCallback } from 'react';
import { 
  Maximize2, 
  Download, 
  Plus, 
  Trash2, 
  Ruler,
  Map,
  ChevronDown,
  Palette,
  Undo2,
  Redo2,
  Save,
  FolderOpen,
  MousePointer2,
  Grab
} from 'lucide-react';
import { SceneObject, RoomDimensions } from '../types';

const OBJECT_TYPES = [
  'Evidence Marker',
  'Victim (Body Outline)',
  'Weapon (Firearm)',
  'Weapon (Knife)',
  'Furniture (Table)',
  'Furniture (Chair)',
  'Bloodstain (Splatter)',
  'Footprint / Shoe Mark',
  'Tire Track',
  'Vehicle (Car)',
  'Doorway / Entrance',
  'Window',
  'Safe / Locker',
  'Computer / Terminal',
  'CCTV Camera'
];

const COLORS = [
  { name: 'Evidence Blue', value: '#3b82f6' },
  { name: 'Critical Red', value: '#ef4444' },
  { name: 'Caution Yellow', value: '#f59e0b' },
  { name: 'Wood Brown', value: '#92400e' },
  { name: 'Floor Grey', value: '#64748b' },
  { name: 'Metal Silver', value: '#94a3b8' },
  { name: 'Dark Void', value: '#1e293b' },
  { name: 'Grass Green', value: '#22c55e' }
];

const SketchTool: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [room, setRoom] = useState<RoomDimensions>({ width: 8, length: 6 });
  const [objects, setObjects] = useState<SceneObject[]>([]);
  const [history, setHistory] = useState<SceneObject[][]>([]);
  const [historyIndex, setHistoryIndex] = useState(-1);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });

  const [currentObject, setCurrentObject] = useState<Omit<SceneObject, 'id'>>({
    type: 'Evidence Marker',
    label: '',
    x: 4,
    y: 3,
    width: 0.5,
    depth: 0.5,
    rotation: 0,
    color: COLORS[0].value
  });

  const pixelsPerMeter = 60;
  const padding = 60;

  const pushToHistory = useCallback((newObjects: SceneObject[]) => {
    const newHistory = history.slice(0, historyIndex + 1);
    newHistory.push(newObjects);
    setHistory(newHistory);
    setHistoryIndex(newHistory.length - 1);
  }, [history, historyIndex]);

  useEffect(() => {
    const saved = localStorage.getItem('forenova_sketch_project');
    if (saved) {
      const data = JSON.parse(saved);
      setRoom(data.room);
      setObjects(data.objects);
      pushToHistory(data.objects);
    } else {
      pushToHistory([]);
    }
  }, []);

  useEffect(() => {
    draw();
  }, [room, objects, selectedId]);

  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    canvas.width = room.width * pixelsPerMeter + padding * 2;
    canvas.height = room.length * pixelsPerMeter + padding * 2;
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    const startX = padding;
    const startY = padding;

    // Room Background
    ctx.fillStyle = '#f8fafc';
    ctx.fillRect(startX, startY, room.width * pixelsPerMeter, room.length * pixelsPerMeter);

    // Grid Dots
    ctx.fillStyle = '#cbd5e1';
    for (let x = 0; x <= room.width; x++) {
      for (let y = 0; y <= room.length; y++) {
        ctx.beginPath();
        ctx.arc(startX + x * pixelsPerMeter, startY + y * pixelsPerMeter, 1, 0, Math.PI * 2);
        ctx.fill();
      }
    }

    // Room Borders
    ctx.strokeStyle = '#1e293b';
    ctx.lineWidth = 3;
    ctx.strokeRect(startX, startY, room.width * pixelsPerMeter, room.length * pixelsPerMeter);

    // Labels
    ctx.fillStyle = '#94a3b8';
    ctx.textAlign = 'center';
    ctx.font = 'bold 12px Inter';
    ctx.fillText(`${room.width}m`, startX + (room.width * pixelsPerMeter) / 2, startY - 20);

    ctx.save();
    ctx.translate(startX - 25, startY + (room.length * pixelsPerMeter) / 2);
    ctx.rotate(-Math.PI / 2);
    ctx.fillText(`${room.length}m`, 0, 0);
    ctx.restore();

    // Draw Objects
    objects.forEach((obj) => {
      ctx.save();
      const drawX = startX + obj.x * pixelsPerMeter;
      const drawY = startY + obj.y * pixelsPerMeter;
      const drawW = obj.width * pixelsPerMeter;
      const drawD = obj.depth * pixelsPerMeter;

      ctx.translate(drawX, drawY);
      ctx.rotate((obj.rotation * Math.PI) / 180);

      // Selection Highlight
      if (selectedId === obj.id) {
        ctx.strokeStyle = '#3b82f6';
        ctx.lineWidth = 4;
        ctx.setLineDash([5, 5]);
        ctx.strokeRect(-drawW / 2 - 4, -drawD / 2 - 4, drawW + 8, drawD + 8);
        ctx.setLineDash([]);
      }

      ctx.fillStyle = obj.color;

      if (obj.type.includes('Body')) {
        ctx.beginPath();
        ctx.ellipse(0, 0, drawW / 2, drawD / 2, 0, 0, Math.PI * 2);
        ctx.fill();
        ctx.strokeStyle = 'white';
        ctx.lineWidth = 2;
        ctx.stroke();
      } else if (obj.type.includes('Bloodstain')) {
        ctx.beginPath();
        ctx.moveTo(drawW / 4, 0);
        for(let i=0; i<12; i++) {
            const angle = (i/12) * Math.PI * 2;
            const r = (drawW/2) * (0.7 + Math.random() * 0.3);
            ctx.lineTo(Math.cos(angle)*r, Math.sin(angle)*r);
        }
        ctx.closePath();
        ctx.fill();
      } else {
        ctx.fillRect(-drawW / 2, -drawD / 2, drawW, drawD);
        ctx.strokeStyle = 'rgba(0,0,0,0.1)';
        ctx.lineWidth = 1;
        ctx.strokeRect(-drawW / 2, -drawD / 2, drawW, drawD);
      }

      // Label
      ctx.rotate(-(obj.rotation * Math.PI) / 180);
      ctx.fillStyle = '#ffffff';
      ctx.font = 'bold 9px Inter';
      ctx.textAlign = 'center';
      ctx.fillText(obj.label || obj.type.split(' ')[0], 0, 4);

      ctx.restore();
    });
  };

  const addObject = () => {
    const newObject: SceneObject = {
      ...currentObject,
      id: Date.now().toString()
    };
    const newObjects = [...objects, newObject];
    setObjects(newObjects);
    pushToHistory(newObjects);
    setSelectedId(newObject.id);
  };

  const removeSelected = () => {
    if (!selectedId) return;
    const newObjects = objects.filter(o => o.id !== selectedId);
    setObjects(newObjects);
    pushToHistory(newObjects);
    setSelectedId(null);
  };

  const undo = () => {
    if (historyIndex > 0) {
      const prev = history[historyIndex - 1];
      setObjects(prev);
      setHistoryIndex(historyIndex - 1);
      setSelectedId(null);
    }
  };

  const redo = () => {
    if (historyIndex < history.length - 1) {
      const next = history[historyIndex + 1];
      setObjects(next);
      setHistoryIndex(historyIndex + 1);
      setSelectedId(null);
    }
  };

  const saveProject = () => {
    localStorage.setItem('forenova_sketch_project', JSON.stringify({ room, objects }));
    alert("Project saved locally.");
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const rect = canvas.getBoundingClientRect();
    const mouseX = (e.clientX - rect.left - padding) / pixelsPerMeter;
    const mouseY = (e.clientY - rect.top - padding) / pixelsPerMeter;

    const clicked = [...objects].reverse().find(obj => (
      mouseX >= obj.x - obj.width / 2 &&
      mouseX <= obj.x + obj.width / 2 &&
      mouseY >= obj.y - obj.depth / 2 &&
      mouseY <= obj.y + obj.depth / 2
    ));

    if (clicked) {
      setSelectedId(clicked.id);
      setIsDragging(true);
      setDragOffset({ x: mouseX - clicked.x, y: mouseY - clicked.y });
    } else {
      setSelectedId(null);
    }
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (!isDragging || !selectedId) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const rect = canvas.getBoundingClientRect();
    const mouseX = (e.clientX - rect.left - padding) / pixelsPerMeter;
    const mouseY = (e.clientY - rect.top - padding) / pixelsPerMeter;

    setObjects(prev => prev.map(obj => 
      obj.id === selectedId 
        ? { ...obj, x: Math.max(0, Math.min(room.width, mouseX - dragOffset.x)), y: Math.max(0, Math.min(room.length, mouseY - dragOffset.y)) } 
        : obj
    ));
  };

  const handleMouseUp = () => {
    if (isDragging) {
      setIsDragging(false);
      pushToHistory(objects);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between bg-[#161b2a] p-4 rounded-xl border border-slate-800">
        <div className="flex items-center gap-4">
          <button onClick={undo} disabled={historyIndex <= 0} className="p-2 rounded-lg hover:bg-slate-800 disabled:opacity-30">
            <Undo2 size={18} />
          </button>
          <button onClick={redo} disabled={historyIndex >= history.length - 1} className="p-2 rounded-lg hover:bg-slate-800 disabled:opacity-30">
            <Redo2 size={18} />
          </button>
          <div className="w-px h-6 bg-slate-800 mx-2" />
          <button onClick={saveProject} className="flex items-center gap-2 text-xs font-bold bg-blue-600 px-4 py-2 rounded-lg hover:bg-blue-700">
            <Save size={14} /> Save Project
          </button>
        </div>
        <div className="flex items-center gap-2">
           <span className="text-[10px] text-slate-500 font-mono uppercase">Interactivity: Drag & Drop Ready</span>
           <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse" />
        </div>
      </div>

      <div className="grid grid-cols-12 gap-8">
        <div className="col-span-12 lg:col-span-4 space-y-4">
          <div className="bg-[#161b2a] border border-slate-800 rounded-xl p-6 space-y-6">
            <div className="space-y-4">
              <h3 className="text-[11px] font-bold text-slate-500 uppercase tracking-widest">Scene Layout</h3>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-xs text-slate-400">Width (m)</label>
                  <input type="number" value={room.width} onChange={(e) => setRoom({ ...room, width: Number(e.target.value) })} className="w-full bg-[#0a0e17] border border-slate-800 rounded-lg px-3 py-2 text-sm" />
                </div>
                <div className="space-y-1">
                  <label className="text-xs text-slate-400">Length (m)</label>
                  <input type="number" value={room.length} onChange={(e) => setRoom({ ...room, length: Number(e.target.value) })} className="w-full bg-[#0a0e17] border border-slate-800 rounded-lg px-3 py-2 text-sm" />
                </div>
              </div>
            </div>

            <div className="pt-4 border-t border-slate-800 space-y-4">
              <h3 className="text-[11px] font-bold text-slate-500 uppercase tracking-widest">Add New Object</h3>
              <div className="space-y-3">
                <select 
                  value={currentObject.type} 
                  onChange={(e) => setCurrentObject({ ...currentObject, type: e.target.value })}
                  className="w-full bg-[#0a0e17] border border-slate-800 rounded-lg px-3 py-2 text-sm"
                >
                  {OBJECT_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
                </select>
                <input 
                  type="text" placeholder="Custom Label" value={currentObject.label}
                  onChange={(e) => setCurrentObject({ ...currentObject, label: e.target.value })}
                  className="w-full bg-[#0a0e17] border border-slate-800 rounded-lg px-3 py-2 text-sm" 
                />
                <div className="flex flex-wrap gap-2">
                  {COLORS.map(c => (
                    <button 
                      key={c.value} onClick={() => setCurrentObject({ ...currentObject, color: c.value })}
                      className={`w-5 h-5 rounded-full border ${currentObject.color === c.value ? 'ring-2 ring-blue-500' : ''}`}
                      style={{ backgroundColor: c.value }}
                    />
                  ))}
                </div>
                <button onClick={addObject} className="w-full bg-slate-800 py-2 rounded-lg text-xs font-bold flex items-center justify-center gap-2">
                  <Plus size={14} /> Place in Center
                </button>
              </div>
            </div>

            {selectedId && (
              <div className="pt-4 border-t border-slate-800 space-y-4 animate-in fade-in">
                <div className="flex justify-between items-center">
                  <h3 className="text-[11px] font-bold text-blue-500 uppercase tracking-widest">Selected Object</h3>
                  <button onClick={removeSelected} className="text-rose-500 hover:bg-rose-500/10 p-1 rounded-md">
                    <Trash2 size={16} />
                  </button>
                </div>
                <div className="space-y-3">
                  <div className="space-y-1">
                    <div className="flex justify-between text-[10px]">
                      <label className="text-slate-400">Rotation</label>
                      <span className="text-blue-400">{objects.find(o => o.id === selectedId)?.rotation}°</span>
                    </div>
                    <input 
                      type="range" min="0" max="360" 
                      value={objects.find(o => o.id === selectedId)?.rotation || 0}
                      onChange={(e) => setObjects(prev => prev.map(o => o.id === selectedId ? { ...o, rotation: Number(e.target.value) } : o))}
                      className="w-full accent-blue-500 h-1 bg-slate-800 rounded-full appearance-none"
                    />
                  </div>
                  <div className="grid grid-cols-2 gap-2">
                    <div className="space-y-1">
                       <label className="text-[10px] text-slate-500">Width (m)</label>
                       <input type="number" step="0.1" value={objects.find(o => o.id === selectedId)?.width || 0.5} onChange={(e) => setObjects(prev => prev.map(o => o.id === selectedId ? { ...o, width: Number(e.target.value) } : o))} className="w-full bg-[#0a0e17] border border-slate-800 rounded-lg px-2 py-1 text-xs" />
                    </div>
                    <div className="space-y-1">
                       <label className="text-[10px] text-slate-500">Depth (m)</label>
                       <input type="number" step="0.1" value={objects.find(o => o.id === selectedId)?.depth || 0.5} onChange={(e) => setObjects(prev => prev.map(o => o.id === selectedId ? { ...o, depth: Number(e.target.value) } : o))} className="w-full bg-[#0a0e17] border border-slate-800 rounded-lg px-2 py-1 text-xs" />
                    </div>
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>

        <div className="col-span-12 lg:col-span-8 space-y-4">
          <div className="bg-[#0a0e17] rounded-2xl border border-slate-800 p-8 flex items-center justify-center min-h-[600px] overflow-auto relative cursor-crosshair shadow-inner">
            <canvas
              ref={canvasRef}
              onMouseDown={handleMouseDown}
              onMouseMove={handleMouseMove}
              onMouseUp={handleMouseUp}
              onMouseLeave={handleMouseUp}
              className="shadow-2xl shadow-black/80 bg-white"
            />
            {!selectedId && <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none opacity-10">
              <Grab size={100} className="text-white" />
            </div>}
          </div>
          <div className="flex justify-between items-center text-[10px] text-slate-500 font-mono uppercase px-2">
            <span>Use mouse to drag objects</span>
            <span className="flex items-center gap-1"><MousePointer2 size={10} /> Selection Active</span>
          </div>
        </div>
      </div>
    </div>
  );
};

