import React, { useState, useCallback, useRef, useEffect } from 'react';
import { 
  CheckCircle2, 
  AlertCircle, 
  Trash2, 
  Archive, 
  Camera, 
  MapPin, 
  ArrowRight,
  Info,
  RefreshCw
} from 'lucide-react';
import { EVIDENCE_DATA } from '../constants';

const STEPS = [
  'Preparation & Photography',
  'Measurement & Location',
  'Collection & Swabbing',
  'Packaging & Labeling',
  'Chain of Custody'
];

const EvidenceSimulator: React.FC = () => {
  const [selectedEvidence, setSelectedEvidence] = useState(EVIDENCE_DATA[0]);
  const [currentStep, setCurrentStep] = useState(0);
  const [feedback, setFeedback] = useState<{ type: 'success' | 'error', text: string } | null>(null);
  const [selectedTools, setSelectedTools] = useState<string[]>([]);
  const [capturedPhoto, setCapturedPhoto] = useState<string | null>(null);
  const [isCameraActive, setIsCameraActive] = useState(false);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const playSound = useCallback((type: 'success' | 'error' | 'click') => {
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      if (!AudioContext) return;
      const ctx = new AudioContext();
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain);
      gain.connect(ctx.destination);
      const now = ctx.currentTime;
      if (type === 'success') {
        osc.frequency.setValueAtTime(880, now);
        osc.frequency.exponentialRampToValueAtTime(1320, now + 0.1);
        gain.gain.setValueAtTime(0.1, now);
        gain.gain.exponentialRampToValueAtTime(0.01, now + 0.2);
        osc.start(now); osc.stop(now + 0.2);
      } else if (type === 'error') {
        osc.type = 'sawtooth';
        osc.frequency.setValueAtTime(150, now);
        gain.gain.setValueAtTime(0.1, now);
        gain.gain.linearRampToValueAtTime(0, now + 0.3);
        osc.start(now); osc.stop(now + 0.3);
      } else {
        osc.frequency.setValueAtTime(1500, now);
        gain.gain.setValueAtTime(0.05, now);
        osc.start(now); osc.stop(now + 0.05);
      }
    } catch (e) {}
  }, []);

  const startCamera = async () => {
    try {
      setIsCameraActive(true);
      const stream = await navigator.mediaDevices.getUserMedia({ video: true });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
    } catch (err) {
      console.error("Camera error:", err);
      setIsCameraActive(false);
      setFeedback({ type: 'error', text: 'Could not access camera. Ensure permissions are granted.' });
    }
  };

  const takePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      ctx?.drawImage(video, 0, 0);
      const data = canvas.toDataURL('image/png');
      setCapturedPhoto(data);
      stopCamera();
      playSound('click');
    }
  };

  const stopCamera = () => {
    if (videoRef.current && videoRef.current.srcObject) {
      const stream = videoRef.current.srcObject as MediaStream;
      stream.getTracks().forEach(track => track.stop());
      setIsCameraActive(false);
    }
  };

  const nextStep = () => {
    if (currentStep === 0) {
        if (!capturedPhoto) {
            playSound('error');
            setFeedback({ type: 'error', text: 'Evidence photography is mandatory!' });
            return;
        }
        if (selectedTools.length === 0) {
            playSound('error');
            setFeedback({ type: 'error', text: 'Select collection tools!' });
            return;
        }
    }

    if (currentStep < STEPS.length - 1) {
      playSound('click');
      setCurrentStep(prev => prev + 1);
      setFeedback(null);
    } else {
      playSound('success');
      setFeedback({ type: 'success', text: 'Case Logged! Evidence ID: #EV-FN' + Math.floor(Math.random()*1000) });
    }
  };

  const restart = () => {
    playSound('click');
    setCurrentStep(0);
    setSelectedTools([]);
    setFeedback(null);
    setCapturedPhoto(null);
    stopCamera();
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h2 className="text-xl font-bold flex items-center gap-2">
          <Archive className="text-blue-500" />
          Evidence Simulation
        </h2>
        <button onClick={restart} className="text-xs bg-slate-800 px-3 py-1 rounded-full flex items-center gap-1 hover:bg-slate-700">
