                <h4 className="text-[10px] font-bold uppercase tracking-widest text-slate-500">Required Kit</h4>
                <div className="flex flex-wrap gap-2">
                  {selectedEvidence.toolsNeeded.map(tool => (
                    <button
                      key={tool}
                      onClick={() => { playSound('click'); setSelectedTools(prev => prev.includes(tool) ? prev.filter(t => t !== tool) : [...prev, tool]) }}
                      className={`px-3 py-1.5 rounded-lg text-[10px] font-bold border transition-all ${
                        selectedTools.includes(tool) ? 'bg-blue-600 border-blue-600 text-white' : 'bg-slate-900 border-slate-800 text-slate-500'
                      }`}
                    >
                      {tool}
                    </button>
                  ))}
                </div>
              </div>
            </div>
          )}

          {currentStep === 1 && (
            <div className="flex flex-col items-center gap-6 py-8">
              <div className="w-32 h-32 rounded-full bg-blue-500/10 flex items-center justify-center border-4 border-blue-500/20 relative">
                 <MapPin size={48} className="text-blue-500" />
                 <div className="absolute inset-0 border-2 border-dashed border-blue-500/30 rounded-full animate-spin-slow" />
              </div>
              <div className="text-center space-y-2 max-w-xs">
                <h4 className="font-bold">Spatial Triangulation</h4>
                <p className="text-xs text-slate-500 leading-relaxed italic">"Measuring distance from Reference Point A (Wall) and Reference Point B (Door)."</p>
              </div>
            </div>
          )}

          {currentStep >= 2 && currentStep < 5 && (
            <div className="w-full space-y-6">
              <div className="bg-slate-900 p-6 rounded-2xl border border-slate-800 relative shadow-inner">
                <div className="flex items-start justify-between mb-4">
                  <div className="space-y-1">
                    <p className="text-[10px] text-blue-500 font-bold uppercase tracking-widest">Evidence Label</p>
                    <h4 className="text-sm font-bold">{selectedEvidence.name}</h4>
                  </div>
                  <div className="bg-slate-800 px-2 py-1 rounded text-[8px] font-mono text-slate-500">ID: FN-{Math.floor(Math.random()*90000)}</div>
                </div>
                <div className="grid grid-cols-2 gap-4 text-[10px] text-slate-400">
                  <div className="space-y-1">
                    <p className="font-bold text-slate-600">PACKAGING</p>
                    <p>{selectedEvidence.packaging}</p>
                  </div>
                  <div className="space-y-1">
                    <p className="font-bold text-slate-600">STORAGE</p>
                    <p>{selectedEvidence.storage} ({selectedEvidence.temperature})</p>
                  </div>
                </div>
              </div>
              <div className="flex items-center gap-3 bg-blue-500/5 p-4 rounded-xl border border-blue-500/10">
                <Info size={16} className="text-blue-500 shrink-0" />
                <p className="text-[10px] text-slate-300">Maintain Chain of Custody. Ensure signature on all seals.</p>
              </div>
            </div>
          )}

          {feedback && (
            <div className={`w-full p-4 rounded-xl border-2 flex items-center gap-3 animate-in slide-in-from-bottom-2 ${
              feedback.type === 'success' ? 'bg-emerald-500/10 border-emerald-500/50 text-emerald-400' : 'bg-rose-500/10 border-rose-500/50 text-rose-400'
            }`}>
              {feedback.type === 'success' ? <CheckCircle2 size={20} /> : <AlertCircle size={20} />}
              <p className="text-xs font-bold">{feedback.text}</p>
            </div>
          )}
        </div>

        <button 
          onClick={nextStep}
          className="mt-8 w-full py-4 bg-blue-600 hover:bg-blue-700 rounded-xl font-bold flex items-center justify-center gap-2 transition-all shadow-xl shadow-blue-500/20 group"
        >
          <span>{currentStep === STEPS.length - 1 ? 'Archive & Finalize' : 'Proceed to ' + STEPS[currentStep + 1]}</span>
          <ArrowRight size={18} className="group-hover:translate-x-1 transition-transform" />
        </button>
      </div>

      <canvas ref={canvasRef} className="hidden" />

      <style>{`
        @keyframes spin-slow {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
        }
        .animate-spin-slow {
          animation: spin-slow 10s linear infinite;
        }
      `}</style>
    </div>
  );
};

