import React, { useState, useCallback } from 'react';
import { 
  CheckCircle2, 
  AlertCircle, 
  Trash2, 
  Archive, 
  MapPin, 
  ArrowRight,
  Info,
  Beaker,
  Thermometer,
  ShieldCheck,
  PackageCheck
} from 'lucide-react';
import { EVIDENCE_DATA } from '../constants';
import { EvidenceType } from '../types';

const STEPS = [
  'Tool Selection',
  'Collection Method',
  'Packaging & Labeling',
  'Chain of Custody'
];

const EvidenceSimulator: React.FC = () => {
  const [selectedEvidence, setSelectedEvidence] = useState<EvidenceType | null>(null);
  const [activeTab, setActiveTab] = useState<'collection' | 'preservation'>('collection');
  const [currentStep, setCurrentStep] = useState(0);
  const [feedback, setFeedback] = useState<{ type: 'success' | 'error', text: string } | null>(null);
  const [selectedTools, setSelectedTools] = useState<string[]>([]);

  const playSound = useCallback((type: 'success' | 'error' | 'click') => {
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      if (!AudioContext) return;
      const ctx = new AudioContext();
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain);
      gain.connect(ctx.destination);
      const now = ctx.currentTime;
      if (type === 'success') {
        osc.frequency.setValueAtTime(880, now);
        osc.frequency.exponentialRampToValueAtTime(1320, now + 0.1);
        gain.gain.setValueAtTime(0.1, now);
        gain.gain.exponentialRampToValueAtTime(0.01, now + 0.2);
        osc.start(now); osc.stop(now + 0.2);
      } else if (type === 'error') {
        osc.type = 'sawtooth';
        osc.frequency.setValueAtTime(150, now);
        gain.gain.setValueAtTime(0.1, now);
        gain.gain.linearRampToValueAtTime(0, now + 0.3);
        osc.start(now); osc.stop(now + 0.3);
      } else {
        osc.frequency.setValueAtTime(1500, now);
        gain.gain.setValueAtTime(0.05, now);
        osc.start(now); osc.stop(now + 0.05);
      }
    } catch (e) {}
  }, []);

  const handleEvidenceSelect = (ev: EvidenceType) => {
    playSound('click');
    setSelectedEvidence(ev);
    setCurrentStep(0);
    setSelectedTools([]);
    setFeedback(null);
  };

  const nextStep = () => {
    if (!selectedEvidence) return;

    if (currentStep === 0 && selectedTools.length === 0) {
      playSound('error');
      setFeedback({ type: 'error', text: 'Select appropriate tools before proceeding!' });
      return;
    }

    if (currentStep < STEPS.length - 1) {
      playSound('click');
      setCurrentStep(prev => prev + 1);
      setFeedback(null);
    } else {
      playSound('success');
      setFeedback({ type: 'success', text: 'Training Module Complete! Evidence safely processed.' });
    }
  };

  const resetModule = () => {
    playSound('click');
    setCurrentStep(0);
    setSelectedTools([]);
    setFeedback(null);
  };

  const getIcon = (name: string) => {
    if (name.includes('Blood')) return '🩸';
    if (name.includes('Print')) return '🖐️';
    if (name.includes('Hair')) return '🧵';
    if (name.includes('HDD')) return '💻';
    return '📦';
  };

  return (
    <div className="space-y-6 max-w-7xl mx-auto">
      <h1 className="text-3xl font-bold tracking-tight">Evidence Handling Training</h1>

      {/* Mode Tabs */}
      <div className="flex gap-4">
        <button 
          onClick={() => { playSound('click'); setActiveTab('collection'); }}
          className={`px-6 py-2 rounded-full text-sm font-bold transition-all ${
            activeTab === 'collection' ? 'bg-blue-600 text-white' : 'bg-slate-800 text-slate-400'
          }`}
        >
          Collection
        </button>
        <button 
          onClick={() => { playSound('click'); setActiveTab('preservation'); }}
          className={`px-6 py-2 rounded-full text-sm font-bold transition-all ${
            activeTab === 'preservation' ? 'bg-blue-600 text-white' : 'bg-slate-800 text-slate-400'
          }`}
        >
          Preservation & Safety
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 min-h-[600px]">
        {/* Sidebar: Evidence Selection */}
        <div className="lg:col-span-3 bg-[#111827] border border-slate-800 rounded-2xl p-6 overflow-y-auto">
          <h3 className="text-sm font-bold text-slate-400 uppercase tracking-widest mb-6">Select Evidence Type</h3>
          <div className="space-y-3">
            {EVIDENCE_DATA.map(ev => (
              <button
                key={ev.id}
                onClick={() => handleEvidenceSelect(ev)}
                className={`w-full p-4 rounded-xl flex items-center gap-4 transition-all text-left ${
                  selectedEvidence?.id === ev.id 
                    ? 'bg-blue-600/10 border border-blue-600 text-blue-400' 
                    : 'bg-slate-900 border border-transparent hover:bg-slate-800 text-slate-300'
                }`}
              >
                <span className="text-2xl">{getIcon(ev.name)}</span>
                <span className="text-sm font-bold">{ev.name}</span>
              </button>
            ))}
          </div>
        </div>

        {/* Main Content Area */}
        <div className="lg:col-span-9 bg-[#111827] border border-slate-800 rounded-2xl p-8 flex flex-col relative overflow-hidden">
          {!selectedEvidence ? (
            <div className="flex-1 flex flex-col items-center justify-center text-center space-y-4 opacity-40">
              <Beaker size={64} className="text-slate-600" />
              <p className="text-lg text-slate-500">Select an evidence type to begin training module.</p>
            </div>
          ) : (
            <div className="flex-1 flex flex-col animate-in fade-in slide-in-from-right-4 duration-300">
              {activeTab === 'collection' ? (
                <div className="space-y-8 flex-1 flex flex-col">
                  {/* Progress Header */}
                  <div className="flex justify-between items-center">
                    <div>
                      <h2 className="text-2xl font-bold text-white">{selectedEvidence.name} Collection</h2>
                      <p className="text-sm text-slate-500 mt-1">Mode: Interactive Simulation</p>
                    </div>
                    <button onClick={resetModule} className="text-xs bg-slate-800 hover:bg-slate-700 px-3 py-1 rounded-lg text-slate-400 flex items-center gap-2">
                      <Trash2 size={12} /> Reset Step
                    </button>
                  </div>

                  {/* Step Indicator */}
                  <div className="flex justify-between px-4">
                    {STEPS.map((step, idx) => (
                      <div key={idx} className="flex flex-col items-center gap-2 relative">
                        <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold z-10 ${
                          idx < currentStep ? 'bg-emerald-500 text-white' : idx === currentStep ? 'bg-blue-600 text-white ring-4 ring-blue-600/20' : 'bg-slate-800 text-slate-500'
                        }`}>
                          {idx < currentStep ? <CheckCircle2 size={16} /> : idx + 1}
                        </div>
                        <span className={`text-[10px] font-bold uppercase tracking-tighter ${idx === currentStep ? 'text-blue-500' : 'text-slate-600'}`}>{step}</span>
                        {idx < STEPS.length - 1 && <div className="absolute top-4 left-10 w-full h-[2px] bg-slate-800 -z-0" />}
                      </div>
                    ))}
                  </div>

                  {/* Simulation Body */}
                  <div className="flex-1 bg-slate-900/50 rounded-3xl border border-slate-800 p-8 flex flex-col justify-center items-center text-center">
                    {currentStep === 0 && (
                      <div className="space-y-6 w-full max-w-lg">
                        <h4 className="text-lg font-bold">Step 1: Required Toolkit</h4>
                        <p className="text-sm text-slate-400">Identify and select all mandatory tools for processing {selectedEvidence.name}.</p>
                        <div className="grid grid-cols-2 gap-3">
                          {selectedEvidence.toolsNeeded.concat(['Generic Box', 'Hammer', 'Plastic Container']).map(tool => (
                            <button
                              key={tool}
                              onClick={() => { playSound('click'); setSelectedTools(prev => prev.includes(tool) ? prev.filter(t => t !== tool) : [...prev, tool]) }}
                              className={`p-4 rounded-xl text-xs font-bold border transition-all ${
                                selectedTools.includes(tool) ? 'bg-blue-600 border-blue-600 text-white shadow-lg' : 'bg-slate-800 border-slate-700 text-slate-500 hover:border-slate-500'
                              }`}
                            >
                              {tool}
                            </button>
                          ))}
                        </div>
                      </div>
                    )}

                    {currentStep === 1 && (
                      <div className="space-y-6">
                         <div className="w-24 h-24 bg-blue-600/10 rounded-full flex items-center justify-center mx-auto ring-8 ring-blue-600/5">
                            <MapPin size={40} className="text-blue-500 animate-bounce" />
                         </div>
                         <div className="max-w-md">
                            <h4 className="text-lg font-bold">Step 2: Methodical Extraction</h4>
                            <p className="text-sm text-slate-400 leading-relaxed mt-2 italic">
                               "Carefully securing the perimeter. Applying the standard procedure for {selectedEvidence.category} evidence recovery..."
                            </p>
                         </div>
                      </div>
                    )}

                    {currentStep === 2 && (
                      <div className="space-y-6 w-full max-w-lg">
                        <h4 className="text-lg font-bold">Step 3: Packaging Standards</h4>
                        <div className="bg-slate-800 p-6 rounded-2xl border-2 border-dashed border-slate-700 text-left space-y-4">
                           <div className="flex items-center gap-3">
                              <PackageCheck className="text-emerald-500" />
                              <span className="text-sm font-bold uppercase tracking-widest text-emerald-400">Packaging Type</span>
                           </div>
                           <p className="text-sm font-mono text-slate-300 bg-black/30 p-4 rounded-lg">
                              RECOMMENDED: {selectedEvidence.packaging.toUpperCase()}
                           </p>
                           <p className="text-[11px] text-slate-500">Ensure all folds are secure and initial across the tape line to prevent unauthorized tampering.</p>
                        </div>
                      </div>
                    )}

                    {currentStep === 3 && (
                      <div className="space-y-6 w-full max-w-lg">
                         <div className="bg-white/5 border border-white/10 p-8 rounded-3xl relative overflow-hidden">
                            <div className="absolute top-0 right-0 p-2 bg-blue-600 text-[8px] font-bold uppercase rotate-45 translate-x-4 -translate-y-2">CERTIFIED</div>
                            <h4 className="font-serif text-xl italic mb-6">Chain of Custody Form</h4>
                            <div className="space-y-3 font-mono text-xs text-left opacity-70">
                               <p>CASE ID: #FN-2024-882</p>
                               <p>EVIDENCE: {selectedEvidence.name.toUpperCase()}</p>
                               <p>OFFICER: TRAINEE INVESTIGATOR</p>
                               <p>DATE: {new Date().toLocaleDateString()}</p>
                            </div>
                         </div>
                      </div>
                    )}

                    {feedback && (
                      <div className={`mt-8 w-full p-4 rounded-2xl flex items-center gap-3 border animate-in slide-in-from-bottom-2 ${
                        feedback.type === 'success' ? 'bg-emerald-500/10 border-emerald-500/30 text-emerald-400' : 'bg-rose-500/10 border-rose-500/30 text-rose-400'
                      }`}>
                        {feedback.type === 'success' ? <CheckCircle2 size={24} /> : <AlertCircle size={24} />}
                        <p className="text-sm font-bold">{feedback.text}</p>
                      </div>
                    )}
                  </div>

                  <button 
                    onClick={nextStep}
                    className="mt-auto w-full py-5 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl font-bold flex items-center justify-center gap-2 transition-all shadow-xl shadow-blue-500/20 active:scale-[0.98]"
                  >
                    {currentStep === STEPS.length - 1 ? 'Archive & Finish Module' : 'Advance to Next Stage'}
                    <ArrowRight size={20} />
                  </button>
                </div>
              ) : (
                <div className="space-y-8 animate-in fade-in duration-500">
                  <div className="flex justify-between items-start">
                    <div>
                      <h2 className="text-2xl font-bold text-white">{selectedEvidence.name} Preservation</h2>
                      <p className="text-sm text-slate-500 mt-1">Mode: Safety & Storage Protocols</p>
                    </div>
                    <div className="p-2 bg-amber-500/20 text-amber-500 rounded-lg">
                       <ShieldCheck size={24} />
                    </div>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                     <div className="bg-slate-900/50 p-6 rounded-3xl border border-slate-800 space-y-4">
                        <div className="flex items-center gap-3 text-blue-400">
                           <Thermometer size={20} />
                           <h4 className="text-xs font-bold uppercase tracking-widest">Temperature Control</h4>
                        </div>
                        <p className="text-2xl font-bold text-white">{selectedEvidence.temperature}</p>
                        <p className="text-xs text-slate-500 leading-relaxed italic">Extreme fluctuations may degrade the biological or chemical integrity of the specimen.</p>
                     </div>

                     <div className="bg-slate-900/50 p-6 rounded-3xl border border-slate-800 space-y-4">
                        <div className="flex items-center gap-3 text-emerald-400">
                           <Info size={20} />
                           <h4 className="text-xs font-bold uppercase tracking-widest">Storage Logistics</h4>
                        </div>
                        <p className="text-lg font-bold text-white">{selectedEvidence.storage}</p>
                        <p className="text-xs text-slate-500 leading-relaxed italic">Always store in restricted access areas to maintain evidentiary viability.</p>
                     </div>
                  </div>

                  <div className="p-8 bg-blue-600/5 border border-blue-600/10 rounded-3xl space-y-4">
                     <h3 className="text-sm font-bold text-blue-500 uppercase tracking-widest">Handling Precautions</h3>
                     <p className="text-slate-300 leading-relaxed italic">
                        "{selectedEvidence.description}"
                     </p>
                  </div>

                  <div className="flex items-center gap-4 bg-rose-500/5 p-4 rounded-2xl border border-rose-500/10">
                     <AlertCircle size={20} className="text-rose-500" />
                     <p className="text-[11px] text-rose-400 font-bold uppercase tracking-widest">Safety Warning: Wear full PPE. Biological hazards may be present even if sample is dry.</p>
                  </div>
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

