        osc.start(now);
        osc.stop(now + 0.05);
      }
    } catch (e) {
      console.warn("Audio Context blocked", e);
    }
  }, []);

  useEffect(() => {
    if (activeTab === 'daily' && !dailyReady && !isGenerating) {
      setIsGenerating(true);
