        </div>

        <div className={`${selectedBook.color} p-8 lg:p-16 shadow-lg relative overflow-hidden`}>
          <div className="max-w-4xl mx-auto relative z-10">
            <h1 className="text-4xl lg:text-6xl font-serif font-bold text-white leading-tight">
              {selectedBook.title}
            </h1>
            <p className="text-white/80 mt-4 text-xl lg:text-2xl font-medium">
              {selectedBook.subtext}
            </p>

            {selectedBook.sourceUrl && (
              <a 
                href={selectedBook.sourceUrl} 
                target="_blank" 
                rel="noopener noreferrer"
                className="mt-8 inline-flex items-center gap-2 bg-white text-slate-900 px-6 py-3 rounded-xl font-bold text-sm hover:scale-105 transition-all shadow-xl"
              >
                Access Full Archive <ExternalLink size={16} />
              </a>
            )}
          </div>
          <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/black-paper.png')] opacity-20 pointer-events-none" />
        </div>

        <div className="flex-1 overflow-y-auto p-8 lg:p-12">
          <div className="max-w-4xl mx-auto space-y-12">
            <div className="text-slate-300 text-lg lg:text-2xl font-serif leading-relaxed first-letter:text-6xl first-letter:font-bold first-letter:mr-3 first-letter:float-left first-letter:text-white">
              {selectedBook.description}
            </div>

            <div className="pt-10 border-t border-slate-800">
              <h3 className="text-sm font-bold text-blue-500 uppercase tracking-widest mb-6">Core Techniques Analyzed</h3>
              <div className="flex flex-wrap gap-3">
                {selectedBook.techniquesUsed.map(tech => (
                  <span key={tech} className="bg-slate-900 border border-slate-800 text-slate-400 px-4 py-2 rounded-xl text-xs font-bold uppercase tracking-wide">
                    {tech}
                  </span>
                ))}
              </div>
            </div>

            <div className="p-8 bg-blue-500/5 rounded-3xl border border-blue-500/10 shadow-inner">
              <h3 className="text-xs font-bold text-blue-400 uppercase tracking-widest mb-3">Final Outcome</h3>
              <p className="text-slate-200 text-lg italic leading-relaxed">"{selectedBook.outcome}"</p>
            </div>

            {/* Related Cases Section */}
            {relatedCases.length > 0 && (
              <div className="pt-10 border-t border-slate-800">
                <h3 className="text-sm font-bold text-slate-400 uppercase tracking-widest mb-6 flex items-center gap-2">
                  <BookOpen size={16} /> Related Investigations
                </h3>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {relatedCases.map(caseRef => (
                    <button 
                      key={caseRef.id}
                      onClick={() => { playSound('click'); setSelectedBook(caseRef); }}
                      className="p-6 rounded-2xl bg-slate-900/40 border border-slate-800 hover:border-blue-500/50 text-left transition-all group"
                    >
                      <span className="text-[9px] font-bold text-blue-500 uppercase tracking-[0.2em]">{caseRef.category}</span>
                      <h4 className="text-white font-bold text-lg mt-1 group-hover:text-blue-400">{caseRef.title}</h4>
                      <div className="mt-4 flex items-center gap-2 text-slate-500 text-xs font-bold">
                        Learn More <ArrowRight size={14} className="group-hover:translate-x-1 transition-transform" />
                      </div>
                    </button>
                  ))}
                </div>
              </div>
            )}

            <div className="flex justify-center pt-16 pb-20">
              <button 
                onClick={() => setSelectedBook(null)}
                className="bg-[#1e293b] hover:bg-slate-700 border border-slate-700 text-white px-8 py-4 rounded-2xl font-bold flex items-center gap-3 transition-all hover:scale-105 shadow-xl shadow-black/50"
              >
                Close Case File
              </button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-8 pb-10">
      <div className="flex items-center gap-8 border-b border-slate-800 pb-0">
        <button 
          onClick={() => { playSound('click'); setActiveTab('books'); }}
          className={`flex items-center gap-2 pb-4 px-1 text-sm font-bold transition-all relative ${
            activeTab === 'books' ? 'text-blue-400' : 'text-slate-500 hover:text-slate-300'
          }`}
        >
          <LibraryIcon size={18} />
          Case Library (Books)
          {activeTab === 'books' && <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-blue-400 shadow-[0_0_10px_rgba(96,165,250,0.5)]" />}
        </button>
        <button 
          onClick={() => { playSound('click'); setActiveTab('daily'); }}
          className={`flex items-center gap-2 pb-4 px-1 text-sm font-bold transition-all relative ${
            activeTab === 'daily' ? 'text-blue-400' : 'text-slate-500 hover:text-slate-300'
          }`}
        >
          <GraduationCap size={18} />
          Daily AI Case
          {activeTab === 'daily' && <div className="absolute bottom-0 left-0 right-0 h-0.5 bg-blue-400 shadow-[0_0_10px_rgba(96,165,250,0.5)]" />}
        </button>
      </div>

      {activeTab === 'books' ? (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 xl:grid-cols-5 gap-8 pt-4">
          {CASE_STUDIES.map((study) => (
            <div 
              key={study.id} 
              className="group cursor-pointer"
              onClick={() => { playSound('click'); setSelectedBook(study); }}
            >
              <div className={`aspect-[3/4] rounded-xl shadow-2xl relative overflow-hidden transition-all duration-500 group-hover:-translate-y-3 border border-white/10 group-hover:ring-8 group-hover:ring-blue-500/10 ${study.color}`}>
                <div className="absolute inset-y-0 left-0 w-5 bg-black/25" />
                <div className="p-6 h-full flex flex-col justify-between">
                  <div className="relative">
                    <span className="text-[10px] font-bold tracking-[0.2em] text-white/60 uppercase">{study.category}</span>
                    <h3 className="text-xl lg:text-2xl font-serif font-bold text-white mt-3 leading-tight drop-shadow-sm">
                      {study.title}
                    </h3>
                  </div>
                  <div className="flex flex-col items-center gap-4 relative">
                    <div className="w-14 h-14 rounded-full border border-white/20 flex items-center justify-center text-white/60 group-hover:text-white group-hover:bg-white/10 transition-all duration-300">
                      <Fingerprint size={32} />
                    </div>
                    <span className="text-[9px] font-bold tracking-[0.1em] text-white/40 uppercase text-center max-w-[120px]">
                      {study.subtext}
                    </span>
                  </div>
                </div>
                <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/leather.png')] opacity-15 pointer-events-none" />
                <div className="absolute inset-0 bg-gradient-to-tr from-transparent via-white/5 to-white/10 opacity-0 group-hover:opacity-100 transition-opacity duration-500" />
              </div>
              <div className="mt-5 text-center px-2">
                <p className="text-sm font-bold text-slate-400 group-hover:text-blue-400 transition-colors duration-300">
                  {study.title}
                </p>
                <p className="text-[10px] text-slate-600 uppercase font-bold mt-1 tracking-tighter">{study.category} DIVISION</p>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="min-h-[500px] flex items-center justify-center">
          {isGenerating ? (
            <div className="bg-[#161b2a] border border-slate-800 rounded-3xl p-12 flex flex-col items-center justify-center text-center animate-in fade-in zoom-in duration-500 w-full max-w-2xl">
              <div className="w-20 h-20 bg-blue-600/20 text-blue-500 rounded-full flex items-center justify-center mb-6 shadow-2xl shadow-blue-500/20">
                <GraduationCap size={40} className="animate-bounce" />
              </div>
              <h3 className="text-2xl font-bold mb-3">Synthesizing Daily Case...</h3>
              <p className="text-base text-slate-500 max-w-lg leading-relaxed">
                Analyzing recent forensic data and simulating a new scenario for investigation. Please wait, Investigator.
              </p>
              <div className="mt-8 flex gap-2">
                {[1, 2, 3].map(i => (
                  <div key={i} className={`w-2 h-2 rounded-full bg-blue-500 animate-pulse [animation-delay:${i * 0.2}s]`} />
                ))}
              </div>
            </div>
          ) : isSubmitted ? (
            <div className="bg-[#161b2a] border border-slate-800 rounded-3xl overflow-hidden w-full max-w-3xl shadow-2xl animate-in zoom-in duration-500 p-12 text-center space-y-8">
               <div className="w-24 h-24 bg-emerald-500/20 text-emerald-500 rounded-full flex items-center justify-center mx-auto shadow-2xl shadow-emerald-500/20">
                  <Trophy size={48} />
               </div>
               <div className="space-y-4">
                  <h3 className="text-3xl font-bold">Investigation Submitted!</h3>
                  <p className="text-slate-400 max-w-md mx-auto">
                    The evidence has been logged and sent to the forensic lab for processing. Your investigative score has been updated.
                  </p>
               </div>

               <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 max-w-xl mx-auto">
                 <div className="bg-slate-900/50 p-6 rounded-2xl border border-slate-800 text-left">
                   <p className="text-[10px] text-slate-500 uppercase font-bold tracking-widest mb-1">Items Collected</p>
                   <p className="text-2xl font-mono text-blue-400 font-bold">{selectedDailyEvidence.length}</p>
                 </div>
                 <div className="bg-slate-900/50 p-6 rounded-2xl border border-slate-800 text-left">
                   <p className="text-[10px] text-slate-500 uppercase font-bold tracking-widest mb-1">Lab ETA</p>
                   <p className="text-2xl font-mono text-emerald-400 font-bold">4 Hours</p>
                 </div>
               </div>

               <div className="pt-8">
                 <button 
                   onClick={resetDaily}
                   className="bg-blue-600 hover:bg-blue-700 text-white px-8 py-3 rounded-xl font-bold flex items-center gap-2 mx-auto transition-all"
                 >
                   <Search size={18} /> New Investigation
                 </button>
               </div>
            </div>
          ) : (
            <div className="bg-[#161b2a] border border-slate-800 rounded-3xl overflow-hidden w-full max-w-4xl shadow-2xl animate-in fade-in slide-in-from-top-4 duration-500">
              <div className="bg-blue-600 p-6 flex items-center justify-between text-white">
                <div className="flex items-center gap-3">
                  <div className="p-2 bg-white/20 rounded-lg">
                    <ShieldCheck size={24} />
                  </div>
                  <div>
                    <h3 className="font-bold text-lg">Daily Briefing</h3>
                    <p className="text-xs text-blue-100 opacity-80 uppercase tracking-widest font-bold">Case #D-{new Date().toISOString().slice(0,10)}</p>
                  </div>
                </div>
                <div className="bg-black/20 px-3 py-1.5 rounded-full text-[10px] font-mono flex items-center gap-2">
                  <Clock size={12} /> STATUS: ACTIVE
                </div>
              </div>

              <div className="p-8 lg:p-12 space-y-8">
                <div className="space-y-4">
                  <div className="flex items-center justify-between">
                    <h4 className="text-sm font-bold text-blue-400 uppercase tracking-widest flex items-center gap-2">
                      <Search size={16} /> Scene Description
                    </h4>
                    <span className="text-[10px] text-slate-500 font-mono">LOCATION: PRIVATE LAB</span>
                  </div>
                  <p className="text-lg lg:text-xl text-slate-300 font-serif leading-relaxed italic border-l-4 border-slate-700 pl-6">
                    "{DAILY_SCENARIOS[0].scenario}"
                  </p>
                </div>

                <div className="pt-8 border-t border-slate-800">
                  <div className="flex flex-col md:flex-row md:items-end justify-between mb-8 gap-4">
                    <div>
                      <h4 className="text-sm font-bold text-slate-400 uppercase tracking-widest">Initial Collection Options</h4>
                      <p className="text-[11px] text-slate-500 mt-1">Enhance your findings by selecting all relevant items. Click to toggle.</p>
                    </div>

                    <div className="flex items-center gap-4 bg-slate-900/50 px-4 py-2 rounded-2xl border border-slate-800">
                       <div className="text-center border-r border-slate-800 pr-4">
                          <p className="text-[9px] text-slate-500 uppercase font-bold tracking-tighter">Total Items</p>
                          <p className="text-sm font-bold text-white">{DAILY_SCENARIOS[0].choices.length}</p>
                       </div>
                       <div className="text-center pl-2">
                          <p className="text-[9px] text-blue-500 uppercase font-bold tracking-tighter">Selected</p>
                          <p className="text-sm font-bold text-blue-400">{selectedDailyEvidence.length}</p>
                       </div>
                    </div>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {DAILY_SCENARIOS[0].choices.map((choice) => (
                      <button
                        key={choice.id}
                        onClick={() => toggleDailyEvidence(choice.id)}
                        className={`p-6 rounded-3xl border-2 transition-all text-left flex flex-col gap-4 group relative overflow-hidden active:scale-95 duration-300 ${
                          selectedDailyEvidence.includes(choice.id)
                            ? 'bg-blue-600/10 border-blue-500 shadow-[0_0_20px_rgba(59,130,246,0.15)] ring-4 ring-blue-500/10 translate-y-[-4px] rotate-[-1deg]'
                            : 'bg-[#0a0e17] border-slate-800 hover:border-slate-600 hover:bg-slate-900/40'
                        }`}
                      >
                        <div className="flex justify-between items-start w-full">
                          <div className={`w-14 h-14 rounded-2xl flex items-center justify-center text-3xl transition-all duration-500 ${
                            selectedDailyEvidence.includes(choice.id) ? 'bg-blue-600 shadow-xl shadow-blue-500/30 scale-110' : 'bg-slate-800 group-hover:bg-slate-700'
                          }`}>
                            {choice.icon}
                          </div>

                          <div className={`w-8 h-8 rounded-full border-2 flex items-center justify-center transition-all duration-500 ${
                            selectedDailyEvidence.includes(choice.id) ? 'bg-blue-500 border-blue-500 text-white rotate-[360deg]' : 'border-slate-800 text-transparent'
                          }`}>
                            <CheckCircle2 size={18} />
                          </div>
                        </div>

                        <div>
                          <p className={`font-bold text-base transition-colors duration-300 ${selectedDailyEvidence.includes(choice.id) ? 'text-blue-400' : 'text-slate-200'}`}>
                            {choice.label}
                          </p>
                          <p className="text-[10px] text-slate-500 uppercase mt-1 tracking-widest font-bold">{choice.type} ANALYSIS REQUIRED</p>
                        </div>

                        {selectedDailyEvidence.includes(choice.id) && (
                          <div className="absolute -top-4 -right-4 w-12 h-12 bg-blue-500/20 blur-xl rounded-full" />
                        )}

                        {/* Interactive Highlight Bar */}
                        <div className={`absolute bottom-0 left-0 right-0 h-1 transition-all duration-500 ${
                          selectedDailyEvidence.includes(choice.id) ? 'bg-blue-500 w-full' : 'bg-transparent w-0'
                        }`} />
                      </button>
                    ))}
                  </div>
                </div>

                <div className="pt-12 flex flex-col items-center gap-6">
                  {/* Selection Status Summary */}
                  <div className={`flex items-center gap-3 p-4 bg-slate-900/60 rounded-2xl border border-slate-800 transition-all duration-500 ${selectedDailyEvidence.length > 0 ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4 pointer-events-none'}`}>
                     <ClipboardCheck size={20} className="text-blue-500" />
                     <span className="text-xs font-medium text-slate-300">
                        Investigator confirmed <span className="text-blue-400 font-bold">{selectedDailyEvidence.length}</span> critical evidence logs.
                     </span>
                  </div>

                  <div className={`transition-all duration-500 ${selectedDailyEvidence.length > 0 ? 'opacity-100 scale-100' : 'opacity-0 scale-95 pointer-events-none'}`}>
                    <button 
                      className="bg-blue-600 hover:bg-blue-700 text-white px-14 py-5 rounded-3xl font-bold flex items-center gap-4 transition-all shadow-2xl shadow-blue-600/40 hover:scale-105 active:scale-95 group"
                      onClick={handleSubmit}
                    >
                      <FlaskConical size={24} className="group-hover:rotate-12 transition-transform" />
                      SUBMIT FOR LAB ANALYSIS
                      <ArrowRight size={24} className="group-hover:translate-x-2 transition-transform" />
                    </button>
                  </div>

                  <div className="flex items-center gap-2 text-amber-500/50 justify-center text-[10px] font-bold uppercase tracking-widest mt-4">
                    <AlertCircle size={14} />
                    Careful: Submitting irrelevant evidence reduces credibility
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default Library;
